import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Product, ColumnConfig, SortConfig, PropertyValue } from '../types';
import { Factory, Edit, Trash2, CheckSquare, Square, ArrowUp, ArrowDown, ChevronLeft, ChevronRight, Eye, Radar, Loader2, AlertCircle, SearchX, RotateCcw, Filter, X, Search, Tag, Trophy } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { EditProductModal } from './EditProductModal';
import { DeleteConfirmationModal } from './DeleteConfirmationModal';
import * as echarts from 'echarts';

export interface FilterItem {
  id: string;
  label: string;
  type: 'search' | 'category' | 'numeric';
  onRemove: () => void;
}

interface DataGridProps {
  data: Product[];
  columns: ColumnConfig[];
  isLoading: boolean;
  onDelete: (ids: string[]) => void;
  onUpdate: (product: Product) => void;
  onBatchUpdate: (ids: string[], updates: Partial<Product>) => void;
  onCategorySelect: (id: string) => void;
  onViewDetails: (product: Product) => void; // New prop for centralized detail view management
  selectedIds: Set<string>;
  onSelectionChange: (ids: Set<string>) => void;
  onClearFilters?: () => void;
  activeFilters?: FilterItem[];
}

const GridSkeleton: React.FC<{ rows: number; cols: number }> = ({ rows, cols }) => (
  <div className="w-full animate-pulse space-y-4 p-4">
    <div className="flex gap-4 mb-8">
      {Array.from({ length: cols }).map((_, i) => (
        <div key={i} className="h-4 bg-slate-100 dark:bg-slate-800 rounded-full flex-1" />
      ))}
    </div>
    {Array.from({ length: rows }).map((_, i) => (
      <div key={i} className="flex gap-4 items-center">
        <div className="w-6 h-6 bg-slate-100 dark:bg-slate-800 rounded-md" />
        {Array.from({ length: cols }).map((_, j) => (
          <div key={j} className={`h-8 bg-slate-50 dark:bg-slate-800/50 rounded-xl flex-1 ${j === 0 ? 'flex-[2]' : ''}`} />
        ))}
      </div>
    ))}
  </div>
);

const QuickRadarPopup: React.FC<{ product: Product; anchorRef: React.RefObject<HTMLDivElement> }> = ({ product, anchorRef }) => {
    const chartRef = useRef<HTMLDivElement>(null);
    const { tProp } = useLanguage();

    useEffect(() => {
        if (!chartRef.current) return;
        const myChart = echarts.init(chartRef.current);
        const props = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度'];
        const values = props.map(p => {
            const v = product.properties?.[p]?.value;
            return typeof v === 'number' ? v : parseFloat(String(v)) || 0;
        });

        myChart.setOption({
            radar: {
                indicator: props.map(p => ({ name: tProp(p).slice(0,6), max: 100 })), 
                shape: 'circle', splitNumber: 3, axisName: { fontSize: 8, color: '#94a3b8' }
            },
            series: [{ type: 'radar', data: [{ value: values, areaStyle: { color: 'rgba(99, 102, 241, 0.3)' }, lineStyle: { color: '#6366f1' } }], symbol: 'none' }]
        });
        return () => myChart.dispose();
    }, [product, tProp]);

    const rect = anchorRef.current?.getBoundingClientRect();
    if (!rect) return null;

    return (
        <div className="fixed z-[100] w-48 h-48 bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-800 p-2 animate-in fade-in zoom-in-95 pointer-events-none" 
             style={{ left: rect.left + 40, top: rect.top - 60 }}>
            <div ref={chartRef} className="w-full h-full" />
        </div>
    );
};

const renderCellContent = (val: any, unit?: string, isLongText = false, isBest = false): React.ReactNode => {
    if (val === null || val === undefined || val === '') {
        return <span className="text-slate-300 dark:text-slate-700 font-mono">-</span>;
    }

    if (typeof val === 'number') {
        if (isNaN(val)) return <span className="text-slate-300 dark:text-slate-700 font-mono">-</span>;
        return (
            <div className={`flex items-baseline gap-1 ${isBest ? 'bg-emerald-100/50 dark:bg-emerald-900/30 px-2 py-0.5 rounded-md -ml-2 border border-emerald-200/50 dark:border-emerald-800/50' : ''}`}>
                <span className={`font-mono font-bold tracking-tight ${isBest ? 'text-emerald-700 dark:text-emerald-400' : 'text-primary-600 dark:text-primary-400'}`}>{val}</span>
                {unit && <span className={`text-[9px] font-black uppercase tracking-tighter ${isBest ? 'text-emerald-500/70' : 'text-slate-400'}`}>{unit}</span>}
                {isBest && <Trophy size={10} className="text-emerald-500 ml-1" />}
            </div>
        );
    }

    const displayStr = typeof val === 'object' ? JSON.stringify(val) : String(val);
    return (
      <span 
        className={`text-slate-700 dark:text-slate-300 font-medium ${isLongText ? 'line-clamp-1 max-w-[240px]' : 'truncate max-w-[180px]'}`} 
        title={displayStr}
      >
        {displayStr}
      </span>
    );
};

// Helper to determine if lower value is better
const isLowBest = (key: string) => {
    const k = key.toLowerCase();
    return k.includes('density') || k.includes('密度') || 
           k.includes('mfr') || k.includes('flow') || k.includes('流动') ||
           k.includes('shrinkage') || k.includes('收缩') ||
           k.includes('haze') || k.includes('雾度') ||
           k.includes('absorption') || k.includes('吸水');
};

export const DataGrid: React.FC<DataGridProps> = ({ data = [], columns = [], isLoading, onDelete, onUpdate, onBatchUpdate, onCategorySelect, onViewDetails, selectedIds = new Set(), onSelectionChange, onClearFilters, activeFilters = [] }) => {
  const { t, tProp } = useLanguage();
  const visibleColumns = useMemo(() => (columns || []).filter((c) => c.visible), [columns]);
  const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deletingIds, setDeletingIds] = useState<string[]>([]);
  // Removed local viewingProduct state - now managed by parent App
  const [hoveredProduct, setHoveredProduct] = useState<Product | null>(null);
  const radarAnchorRef = useRef<HTMLDivElement>(null);

  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 15;

  const sortedData = useMemo(() => {
    if (!data) return [];
    if (!sortConfig) return data;
    return [...data].sort((a, b) => {
      const aProp = a.properties?.[sortConfig.key];
      const bProp = b.properties?.[sortConfig.key];
      let aV = aProp?.value ?? (a as any)[sortConfig.key] ?? '';
      let bV = bProp?.value ?? (b as any)[sortConfig.key] ?? '';

      // Handle nulls always at bottom
      if (aV === '' || aV === null || aV === undefined) return 1;
      if (bV === '' || bV === null || bV === undefined) return -1;

      const aN = parseFloat(String(aV)), bN = parseFloat(String(bV));
      if (!isNaN(aN) && !isNaN(bN)) return sortConfig.direction === 'asc' ? aN - bN : bN - aN;
      return sortConfig.direction === 'asc' ? String(aV).localeCompare(String(bV)) : String(bV).localeCompare(String(aV));
    });
  }, [data, sortConfig]);

  const paginatedData = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return sortedData.slice(start, start + pageSize);
  }, [sortedData, currentPage]);

  const totalPages = Math.ceil(sortedData.length / pageSize);

  useEffect(() => {
    if (currentPage > totalPages && totalPages > 0) { setCurrentPage(totalPages); }
  }, [totalPages, currentPage]);

  // Determine extremes for highlighting within the current view
  const columnExtremes = useMemo(() => {
    const extremes: Record<string, number> = {};
    const visibleCols = columns.filter(c => !c.isSystem && c.visible);

    visibleCols.forEach(col => {
        const key = col.key;
        const lowBest = isLowBest(key);
        let bestVal = lowBest ? Infinity : -Infinity;
        let found = false;

        paginatedData.forEach(p => {
            const val = p.properties?.[key]?.value;
            const num = parseFloat(String(val));
            if (!isNaN(num)) {
                found = true;
                if (lowBest) {
                    if (num < bestVal) bestVal = num;
                } else {
                    if (num > bestVal) bestVal = num;
                }
            }
        });
        if (found && bestVal !== Infinity && bestVal !== -Infinity) {
            extremes[key] = bestVal;
        }
    });
    return extremes;
  }, [paginatedData, columns]);

  const toggleSelection = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id); else next.add(id);
    onSelectionChange(next);
  };

  const toggleAllSelection = () => {
    if (selectedIds.size === paginatedData.length && paginatedData.length > 0) { onSelectionChange(new Set()); }
    else { onSelectionChange(new Set(paginatedData.map(p => p.id))); }
  };

  if (isLoading) return <GridSkeleton rows={10} cols={visibleColumns.length || 5} />;

  if (!isLoading && data.length === 0) {
      return (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/50 dark:bg-slate-900/30 rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800">
              <div className="w-20 h-20 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center shadow-glass mb-6">
                  <SearchX size={32} className="text-slate-300 dark:text-slate-600" />
              </div>
              <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100 mb-2">未找到匹配结果</h3>
              <p className="text-sm text-slate-500 max-w-xs mx-auto tracking-tight mb-6">尝试调整您的过滤条件或搜索关键词以获取更多结果。</p>
              {onClearFilters && (
                  <button onClick={onClearFilters} className="flex items-center gap-2 px-5 py-2.5 bg-primary-600 hover:bg-primary-500 text-white rounded-xl shadow-lg shadow-primary-500/20 font-bold text-xs transition-all active:scale-95">
                      <RotateCcw size={14} /> 重置所有筛选
                  </button>
              )}
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col relative overflow-hidden group/grid">
      {/* Active Filters Bar */}
      {activeFilters.length > 0 && (
          <div className="px-6 py-3 bg-white/50 dark:bg-slate-950/50 border-b border-slate-100 dark:border-slate-800 flex items-center gap-3 shrink-0 overflow-x-auto custom-scrollbar-horizontal backdrop-blur-sm animate-in slide-in-from-top-1">
              <div className="flex items-center gap-1.5 text-[10px] font-black text-slate-400 uppercase tracking-widest shrink-0">
                  <Filter size={12} /> {activeFilters.length} Active Filters
              </div>
              <div className="h-4 w-px bg-slate-200 dark:bg-slate-800 shrink-0 mx-1"></div>

              {activeFilters.map(f => (
                  <div key={f.id} className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold border shadow-sm transition-all animate-in zoom-in duration-200 ${
                      f.type === 'search' 
                      ? 'bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 border-blue-100 dark:border-blue-800' 
                      : 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 border-primary-100 dark:border-primary-800'
                  }`}>
                      {f.type === 'search' ? <Search size={10} /> : <Tag size={10} />}
                      <span>{f.label}</span>
                      <button onClick={f.onRemove} className="p-0.5 rounded-full hover:bg-white/50 dark:hover:bg-black/20 transition-colors ml-1">
                          <X size={12} />
                      </button>
                  </div>
              ))}

              {onClearFilters && activeFilters.length > 1 && (
                  <button 
                    onClick={onClearFilters} 
                    className="ml-auto text-[10px] font-bold text-slate-400 hover:text-rose-500 hover:underline transition-colors whitespace-nowrap px-2"
                  >
                      Clear All
                  </button>
              )}
          </div>
      )}

      <div className="flex-1 overflow-auto custom-scrollbar">
        <table className="w-full text-sm text-left border-separate border-spacing-0">
          <thead className="sticky top-0 z-30 bg-white/90 dark:bg-slate-950/90 backdrop-blur-xl shadow-sm">
            <tr>
              <th className="px-4 py-4 w-12 border-b border-slate-100 dark:border-slate-800">
                <button onClick={toggleAllSelection} className="text-slate-400 hover:text-primary-500 transition-colors">
                    {selectedIds.size > 0 && selectedIds.size === paginatedData.length ? <CheckSquare size={18} className="text-primary-500" /> : <Square size={18} />}
                </button>
              </th>
              {visibleColumns.map((col) => (
                <th key={col.key} className="px-4 py-4 font-black text-[10px] text-slate-400 uppercase tracking-[0.15em] border-b border-slate-100 dark:border-slate-800 cursor-pointer hover:text-primary-600 transition-colors group/head" onClick={() => setSortConfig({ key: col.key, direction: sortConfig?.key === col.key && sortConfig.direction === 'asc' ? 'desc' : 'asc' })}>
                  <div className="flex items-center gap-1.5">{tProp(col.label)}<span className={`transition-all duration-300 ${sortConfig?.key === col.key ? 'opacity-100 scale-100' : 'opacity-0 scale-75 group-hover/head:opacity-40'}`}>{sortConfig?.key === col.key && sortConfig.direction === 'desc' ? <ArrowDown size={12} /> : <ArrowUp size={12} />}</span></div>
                </th>
              ))}
              <th className="px-4 py-4 border-b border-slate-100 dark:border-slate-800 text-right w-24 font-black text-[10px] text-slate-400 uppercase tracking-widest">操作</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50 dark:divide-slate-900">
            {paginatedData.map((p) => (
                <tr 
                    key={p.id} 
                    className={`group transition-all duration-200 cursor-pointer ${selectedIds.has(p.id) ? 'bg-primary-50/40 dark:bg-primary-950/20' : 'hover:bg-slate-50/50 dark:hover:bg-slate-900/40'}`} 
                    onClick={() => toggleSelection(p.id)}
                    onDoubleClick={() => onViewDetails(p)}
                >
                    <td className="px-4 py-3.5" onClick={e => e.stopPropagation()}><button onClick={() => toggleSelection(p.id)} className={`transition-colors ${selectedIds.has(p.id) ? "text-primary-500" : "text-slate-300 group-hover:text-slate-400"}`}>{selectedIds.has(p.id) ? <CheckSquare size={16} /> : <Square size={16} />}</button></td>
                    {visibleColumns.map((col) => {
                        // Check if this cell contains the best value for this column
                        let isBest = false;
                        if (!col.isSystem) {
                            const val = p.properties?.[col.key]?.value;
                            const numVal = parseFloat(String(val));
                            if (!isNaN(numVal) && columnExtremes[col.key] !== undefined && columnExtremes[col.key] === numVal) {
                                isBest = true;
                            }
                        }

                        return (
                            <td key={col.key} className="px-4 py-3.5 whitespace-nowrap">
                                {col.key === 'gradeName' ? (
                                    <div className="flex items-center gap-2">
                                        <span className="font-bold text-slate-800 dark:text-white group-hover:text-primary-600 dark:group-hover:text-primary-400 transition-colors">{p.gradeName}</span>
                                        <div onMouseEnter={(e) => { e.stopPropagation(); setHoveredProduct(p); }} onMouseLeave={() => setHoveredProduct(null)} className="cursor-help text-indigo-500 opacity-0 group-hover:opacity-100 transition-all scale-75 group-hover:scale-100"><Radar size={14} /></div>
                                    </div>
                                ) : col.key === 'manufacturer' ? (
                                    <div className="flex items-center gap-1.5"><Factory size={12} className="text-slate-300 dark:text-slate-600" /><span className="text-slate-500 dark:text-slate-400 font-medium text-xs truncate max-w-[120px]">{p.manufacturer}</span></div>
                                ) : (
                                    renderCellContent(p.properties?.[col.key]?.value, p.properties?.[col.key]?.unit, col.key.includes('应用'), isBest)
                                )}
                            </td>
                        );
                    })}
                    <td className="px-4 py-3.5 text-right" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-all translate-x-2 group-hover:translate-x-0">
                            <button onClick={() => onViewDetails(p)} className="p-1.5 text-slate-400 hover:text-primary-500 hover:bg-primary-50 dark:hover:bg-primary-900/30 rounded-lg transition-all" title={t('details')}><Eye size={14} /></button>
                            <button onClick={() => setEditingProduct(p)} className="p-1.5 text-slate-400 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/30 rounded-lg transition-all" title={t('editProduct')}><Edit size={14} /></button>
                        </div>
                    </td>
                </tr>
            ))}
          </tbody>
        </table>
      </div>
      {hoveredProduct && <QuickRadarPopup product={hoveredProduct} anchorRef={radarAnchorRef} />}
      <div ref={radarAnchorRef} className="hidden" />
      <div className="flex items-center justify-between px-6 py-4 bg-white/80 dark:bg-slate-950/80 border-t border-slate-100 dark:border-slate-800 backdrop-blur-xl z-20">
         <div className="flex items-center gap-4"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('showing')} <span className="text-slate-700 dark:text-slate-200">{paginatedData.length}</span> / <span className="text-slate-700 dark:text-slate-200">{sortedData.length}</span></span>{selectedIds.size > 0 && <div className="h-4 w-px bg-slate-200 dark:bg-slate-800" />}{selectedIds.size > 0 && <span className="text-[10px] font-black text-primary-500 uppercase tracking-widest animate-in fade-in slide-in-from-left-2">{selectedIds.size} {t('selected')}</span>}</div>
         <div className="flex items-center gap-4"><div className="flex items-center gap-1"><button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="p-2 border border-slate-200 dark:border-slate-800 rounded-xl disabled:opacity-20 hover:bg-slate-50 dark:hover:bg-slate-900 text-slate-500 transition-all active:scale-95"><ChevronLeft size={16} /></button><div className="px-4 flex items-center gap-2"><span className="text-xs font-black tabular-nums text-slate-700 dark:text-slate-200">{currentPage}</span><span className="text-[10px] font-bold text-slate-300 dark:text-slate-700">/</span><span className="text-xs font-bold text-slate-400 tabular-nums">{totalPages || 1}</span></div><button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages || totalPages === 0} className="p-2 border border-slate-200 dark:border-slate-800 rounded-xl disabled:opacity-20 hover:bg-slate-50 dark:hover:bg-slate-900 text-slate-500 transition-all active:scale-95"><ChevronRight size={16} /></button></div></div>
      </div>
      <EditProductModal isOpen={!!editingProduct} onClose={() => setEditingProduct(null)} product={editingProduct} onSave={async p => { onUpdate(p); setEditingProduct(null); return true; }} />
      <DeleteConfirmationModal isOpen={deletingIds.length > 0} onClose={() => setDeletingIds([])} onConfirm={() => { onDelete(deletingIds); setDeletingIds([]); }} productNames={deletingIds.map(id => data.find(p => p.id === id)?.gradeName || 'Unknown')} />
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Category } from '../types';
import { ChevronRight, Layers, Search, X, CheckSquare, Square, FolderOpen, Folder, ChevronsUp, ChevronsDown } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface TreeSidebarProps {
  categories: Category[];
  selectedCategoryIds: Set<string>;
  onToggleCategory: (id: string) => void;
  onClearCategories: () => void;
  totalCount?: number;
  counts?: Record<string, number>;
}

const TreeNode: React.FC<{
  category: Category;
  selectedIds: Set<string>;
  onToggle: (id: string) => void;
  depth: number;
  forceExpand?: boolean | null; // Changed to allow tri-state (null = default behavior)
  counts?: Record<string, number>;
  isLast?: boolean; 
}> = ({ category, selectedIds, onToggle, depth, forceExpand = null, counts = {}, isLast = false }) => {
  const [isExpanded, setIsExpanded] = useState(depth < 1); 
  const hasChildren = category.children && category.children.length > 0;
  const isSelected = selectedIds.has(category.id);
  const { language } = useLanguage();

  useEffect(() => { 
      if (forceExpand !== null) {
          setIsExpanded(forceExpand);
      }
  }, [forceExpand]);

  // If forceExpand is active, it overrides local state, otherwise allow toggle
  const displayOpen = forceExpand !== null ? forceExpand : isExpanded;
  const count = counts[category.id] || 0;

  const handleToggle = (e: React.MouseEvent) => {
      e.stopPropagation();
      onToggle(category.id);
  };

  const handleExpand = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (hasChildren) setIsExpanded(!displayOpen);
  };

  return (
    <div className="select-none relative">
      {/* Connector Line for current node relative to parent */}
      {depth > 0 && (
          <div 
            className="absolute border-l-2 border-slate-200 dark:border-slate-800 h-full top-0"
            style={{ left: `${(depth - 1) * 16 + 20}px`, height: isLast ? '20px' : '100%' }}
          >
             {/* Horizontal connector */}
             <div className="absolute top-[20px] left-0 w-3 border-t-2 border-slate-200 dark:border-slate-800"></div>
          </div>
      )}

      <div
        className={`
          flex items-center px-2 py-1.5 cursor-pointer text-sm transition-all duration-200 mx-1 rounded-lg relative group active:scale-[0.98]
          ${isSelected 
            ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 font-bold' 
            : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 hover:text-slate-900 dark:hover:text-slate-200'}
        `}
        style={{ marginLeft: `${depth * 16}px` }}
        onClick={handleToggle}
      >
        {/* Toggle Expand Button */}
        <div 
            onClick={handleExpand}
            className={`p-0.5 mr-1 rounded-md transition-all duration-200 ${hasChildren ? 'hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-400' : 'opacity-0 pointer-events-none'}`}
        >
            <ChevronRight size={14} className={`transition-transform duration-200 ${displayOpen && hasChildren ? 'rotate-90' : ''}`} />
        </div>

        {/* Checkbox UI */}
        <div className={`mr-2 transition-colors ${isSelected ? 'text-primary-500' : 'text-slate-300 group-hover:text-slate-400'}`}>
            {isSelected ? <CheckSquare size={16} /> : <Square size={16} />}
        </div>

        {/* Icon based on state */}
        <div className={`mr-2 transition-colors ${isSelected ? 'text-primary-500' : 'text-slate-400'}`}>
             {hasChildren ? (displayOpen ? <FolderOpen size={14} /> : <Folder size={14} />) : null}
        </div>

        <span className="truncate relative z-10 flex-1 tracking-tight">{language === 'en' && category.nameEn ? category.nameEn : category.name}</span>

        {count > 0 && (
            <span className={`ml-2 px-1.5 py-0.5 rounded-md text-[9px] font-bold ${isSelected ? 'bg-primary-200 dark:bg-primary-800 text-primary-700 dark:text-primary-200' : 'bg-slate-100 dark:bg-slate-800 text-slate-400 dark:text-slate-500 group-hover:bg-white dark:group-hover:bg-slate-700'}`}>
                {count}
            </span>
        )}
      </div>

      <div 
        className={`overflow-hidden transition-all duration-300 ease-in-out ${displayOpen ? 'max-h-[800px] opacity-100' : 'max-h-0 opacity-0'}`}
      >
        <div className="relative">
          {/* Vertical Guide Line for Children */}
          {hasChildren && displayOpen && (
             <div className="absolute left-[20px] top-0 bottom-0 border-l-2 border-slate-100 dark:border-slate-800" style={{ left: `${depth * 16 + 20}px` }}></div>
          )}

          {hasChildren && category.children!.map((child, idx) => (
            <TreeNode
              key={child.id}
              category={child}
              selectedIds={selectedIds}
              onToggle={onToggle}
              depth={depth + 1}
              forceExpand={forceExpand}
              counts={counts}
              isLast={idx === category.children!.length - 1}
            />
          ))}
        </div>
      </div>
    </div>
  );
};

export const TreeSidebar: React.FC<TreeSidebarProps> = ({ categories, selectedCategoryIds, onToggleCategory, onClearCategories, totalCount = 0, counts = {} }) => {
  const { t, language } = useLanguage();
  const [searchTerm, setSearchTerm] = useState('');
  const [globalExpand, setGlobalExpand] = useState<boolean | null>(null);

  const filterCategories = (cats: Category[], term: string): Category[] => {
    return cats.reduce<Category[]>((acc, cat) => {
        const name = language === 'en' && cat.nameEn ? cat.nameEn : cat.name;
        const matches = name.toLowerCase().includes(term.toLowerCase());
        let filteredChildren: Category[] = [];

        if (cat.children) {
            filteredChildren = filterCategories(cat.children, term);
        }

        if (matches || filteredChildren.length > 0) {
            acc.push({ ...cat, children: filteredChildren });
        }
        return acc;
    }, []);
  };

  const displayedCategories = useMemo(() => {
      if (!searchTerm.trim()) return categories;
      return filterCategories(categories, searchTerm);
  }, [categories, searchTerm, language]);

  const hasSelection = selectedCategoryIds.size > 0;

  // Determine expansion state: Search active forces expand, otherwise manual or global toggle
  const effectiveExpandState = searchTerm ? true : globalExpand;

  return (
    <div className="flex flex-col h-full bg-transparent">
      <div className="p-4 pb-2 shrink-0 space-y-3">
        {/* Search & Expand Controls */}
        <div className="flex gap-2">
            <div className="relative group flex-1">
                <Search className="absolute left-3 top-2.5 text-slate-400 group-focus-within:text-primary-500 transition-colors" size={16} />
                <input 
                    type="text" 
                    placeholder={t('searchCategories')} 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-9 pr-8 py-2 bg-white/50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-medium focus:ring-2 focus:ring-primary-500/20 focus:border-primary-500 outline-none transition-all placeholder:text-slate-400 shadow-sm"
                />
                {searchTerm && <button onClick={() => setSearchTerm('')} className="absolute right-2.5 top-2 text-slate-400 hover:text-slate-600"><X size={14} /></button>}
            </div>

            <button 
                onClick={() => setGlobalExpand(true)} 
                className="p-2 rounded-xl bg-white/50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 text-slate-400 hover:text-primary-500 hover:bg-white dark:hover:bg-slate-800 transition-all"
                title="Expand All"
            >
                <ChevronsDown size={16} />
            </button>
            <button 
                onClick={() => setGlobalExpand(false)} 
                className="p-2 rounded-xl bg-white/50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 text-slate-400 hover:text-primary-500 hover:bg-white dark:hover:bg-slate-800 transition-all"
                title="Collapse All"
            >
                <ChevronsUp size={16} />
            </button>
        </div>

        {/* All Products Root Node (Reset Button) */}
        <div 
            className={`
              flex items-center justify-between px-4 py-3 rounded-xl cursor-pointer transition-all duration-200 border group active:scale-[0.98] mx-1
              ${!hasSelection 
                ? 'bg-gradient-to-r from-primary-600 to-indigo-600 text-white shadow-lg shadow-primary-500/20 border-transparent' 
                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 hover:border-primary-200 hover:bg-primary-50/50 dark:hover:bg-slate-700'
              }
            `}
            onClick={onClearCategories}
        >
            <div className="flex items-center gap-3">
                <div className={`p-1.5 rounded-lg ${!hasSelection ? 'bg-white/20' : 'bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-400'}`}>
                    <Layers size={16} />
                </div>
                <span className="font-bold text-sm tracking-wide">{t('allProducts')}</span>
            </div>
            <span className={`px-2 py-0.5 rounded-md text-[10px] font-black ${!hasSelection ? 'bg-white/20 text-white' : 'bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-400'}`}>{totalCount}</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto px-2 custom-scrollbar pb-6 pt-1">
        {displayedCategories.length > 0 ? (
            displayedCategories.map((cat, idx) => (
                <TreeNode
                    key={cat.id}
                    category={cat}
                    selectedIds={selectedCategoryIds}
                    onToggle={onToggleCategory}
                    depth={0}
                    forceExpand={effectiveExpandState}
                    counts={counts}
                    isLast={idx === displayedCategories.length - 1}
                />
            ))
        ) : (
            <div className="text-center py-12 text-xs text-slate-400 italic flex flex-col items-center gap-2">
                <Search size={24} className="opacity-20" />
                No matching categories
            </div>
        )}
      </div>
    </div>
  );
};

