                        m.role === 'user' ? 'bg-slate-900 text-white rounded-tr-none' : 
                        m.role === 'system' ? 'bg-rose-50 dark:bg-rose-950/30 text-rose-700 dark:text-rose-200 border border-rose-100 dark:border-rose-900/50' :
                        'bg-white dark:bg-slate-800 border dark:border-slate-700 rounded-tl-none text-slate-700 dark:text-slate-200'
