import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Search, SlidersHorizontal, Upload, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Clock, Download, Loader2, ArrowRight, Filter, ChevronDown, Sparkles, Hash, Beaker, Check, LayoutGrid, BarChart2, CheckSquare, Square, Palette } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme, ColorTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  onAiSearch?: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
  showAdvancedFilters: boolean;
  onToggleFilters: () => void;
  activeFilterCount: number;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, onAiSearch, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange, showAdvancedFilters, onToggleFilters, activeFilterCount
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme, colorTheme, setColorTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Advanced Filtering Syntax Suggestions
  const filterSuggestions = useMemo(() => {
      const parts = searchQuery.split(' ');
      const lastToken = parts[parts.length - 1];
      if (lastToken.includes(':')) return [];

      const availableProps = columns
          .filter(c => !c.isSystem)
          .map(c => ({
              key: c.key,
              label: tProp(c.label)
          }));

      if (!lastToken) return availableProps.slice(0, 5);

      return availableProps.filter(p => 
          p.label.toLowerCase().includes(lastToken.toLowerCase()) ||
          p.key.toLowerCase().includes(lastToken.toLowerCase())
      ).slice(0, 5);
  }, [columns, searchQuery, tProp]);

  // Check if all dynamic columns are currently visible
  const areAllDynamicVisible = useMemo(() => {
    const dynamicCols = columns.filter(c => !c.isSystem);
    return dynamicCols.length > 0 && dynamicCols.every(c => c.visible);
  }, [columns]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); inputRef.current?.focus(); }
    };
    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) setIsColumnMenuOpen(false);
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) setIsUserMenuOpen(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) try { setSearchHistory(JSON.parse(savedHistory)); } catch (e) {}
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const saveToHistory = (query: string) => {
      const clean = query.trim();
      if (!clean) return;
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 8);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const removeFromHistory = (e: React.MouseEvent, query: string) => {
      e.stopPropagation();
      setSearchHistory(prev => {
          const updated = prev.filter(item => item !== query);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      // Index calc: 0 = AI Suggestion (if active), then Suggestions, then History
      const showAiOption = !!(onAiSearch && searchQuery.trim().length > 2);
      const suggestionsCount = filterSuggestions.length;
      const historyCount = searchHistory.length;
      const totalItems = (showAiOption ? 1 : 0) + suggestionsCount + historyCount;

      if (showHistory && totalItems > 0) {
          if (e.key === 'ArrowDown') { e.preventDefault(); setHistoryIndex(prev => (prev + 1) % totalItems); return; }
          if (e.key === 'ArrowUp') { e.preventDefault(); setHistoryIndex(prev => (prev - 1 + totalItems) % totalItems); return; }
      }
      if (e.key === 'Enter') {
          e.preventDefault();
          if (historyIndex >= 0 && showHistory) {
              let currentIndex = historyIndex;

              // 1. Handle AI Option
              if (showAiOption) {
                  if (currentIndex === 0) {
                      onAiSearch?.(searchQuery);
                      setShowHistory(false);
                      setHistoryIndex(-1);
                      inputRef.current?.blur();
                      return;
                  }
                  currentIndex--; // Shift for next checks
              }

              // 2. Handle Filter Suggestions
              if (currentIndex < suggestionsCount) {
                  applySuggestion(filterSuggestions[currentIndex].label);
                  setHistoryIndex(-1);
                  return;
              }
              currentIndex -= suggestionsCount;

              // 3. Handle History
              if (currentIndex < historyCount) {
                  const histItem = searchHistory[currentIndex];
                  onSearchChange(histItem);
                  saveToHistory(histItem);
                  setHistoryIndex(-1);
                  setShowHistory(false);
              }
          } else { 
              saveToHistory(searchQuery); 
              setShowHistory(false); 
              setHistoryIndex(-1); 
              inputRef.current?.blur(); 
          }
      }
      if (e.key === 'Escape') { setShowHistory(false); setHistoryIndex(-1); inputRef.current?.blur(); }
  };

  const applySuggestion = (label: string) => {
      const parts = searchQuery.split(' ');
      parts[parts.length - 1] = `${label}:`;
      const newQuery = parts.join(' ');
      onSearchChange(newQuery);
      inputRef.current?.focus();
      setHistoryIndex(-1);
  };

  const colors: { id: ColorTheme, color: string, label: string }[] = [
      { id: 'indigo', color: '#4f46e5', label: 'Indigo' },
      { id: 'emerald', color: '#059669', label: 'Emerald' },
      { id: 'blue', color: '#2563eb', label: 'Blue' },
      { id: 'rose', color: '#e11d48', label: 'Rose' },
      { id: 'amber', color: '#d97706', label: 'Amber' },
      { id: 'violet', color: '#7c3aed', label: 'Violet' },
  ];

  return (
    <div className="w-full flex flex-col gap-2 px-6 py-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-b border-slate-200 dark:border-slate-800 shadow-sm relative z-[100]">
      <div className="flex items-center justify-between gap-6">
        {/* Search Bar Container */}
        <div className="flex-1 max-w-3xl relative z-[150]">
            <div className="relative group transition-all duration-300">
                <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                    {isSearching ? <Loader2 className="text-primary-500 animate-spin" size={18} /> : <Search className="text-slate-400 group-focus-within:text-primary-500 transition-colors" size={18} />}
                </div>
                <input
                    ref={inputRef}
                    type="text"
                    value={searchQuery}
                    onChange={(e) => { onSearchChange(e.target.value); setHistoryIndex(-1); }}
                    onFocus={() => { setShowHistory(true); setHistoryIndex(-1); }}
                    onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                    onKeyDown={handleInputKeyDown}
                    placeholder={t('searchPlaceholder')}
                    className="block w-full pl-12 pr-20 py-3.5 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl text-sm font-medium shadow-inner outline-none focus:ring-4 focus:ring-primary-500/10 focus:border-primary-500/30 transition-all text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
                />
                <div className="absolute inset-y-0 right-4 flex items-center gap-2">
                    {searchQuery && (
                        <>
                            <button onClick={() => onSearchChange('')} className="p-1 text-slate-400 hover:text-slate-600 transition-colors"><X size={14} /></button>
                            {onAiSearch && (
                                <button 
                                    onClick={() => onAiSearch(searchQuery)} 
                                    className="p-1.5 text-primary-500 bg-primary-50 dark:bg-primary-900/30 hover:bg-primary-100 dark:hover:bg-primary-900/50 rounded-lg transition-colors ml-1 shadow-sm"
                                    title="Ask ResinAI"
                                >
                                    <Sparkles size={16} />
