          });
      });
      return items;
  }, [searchQuery, selectedCategoryIds, categoryNameMap]);

  // Determine context data for AI: if items are selected, use them, otherwise use current filtered view
  const aiContextData = useMemo(() => {
      return selectedIds.size > 0 ? productsToCompare : filteredData;
  }, [selectedIds, productsToCompare, filteredData]);

  const handleAiAnalysis = () => {
      setAiPrompt("Please analyze the selected products. Compare their key properties (Density, MFR, Mechanical) and identify any outliers or unique characteristics. Suggest potential applications based on their specifications.");
      setActiveView('ai');
  };

  const handleAiSearch = (query: string) => {
      setAiPrompt(query);
      setActiveView('ai');
  };

  // Reset initial prompt when leaving AI view so it doesn't auto-trigger next time if not intended
  useEffect(() => {
      if (activeView !== 'ai') setAiPrompt(undefined);
  }, [activeView]);

  if (!currentUser) return <AuthScreen onLogin={handleLogin} />;

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 font-sans text-slate-900 dark:text-slate-100 overflow-hidden transition-colors duration-300">
      <ToastContainer toasts={toasts} removeToast={(id) => setToasts(prev => prev.filter(t => t.id !== id))} />

      <nav className="w-16 md:w-20 bg-slate-900 dark:bg-slate-950 flex flex-col items-center py-6 gap-6 z-[70] shrink-0 border-r border-white/5 shadow-2xl">
         <div className="w-12 h-12 bg-primary-600 rounded-2xl flex items-center justify-center shadow-lg shadow-primary-900/40 mb-2 overflow-hidden relative group cursor-pointer" onClick={() => setActiveView('dashboard')}>
            <Microscope size={24} className="text-white group-hover:rotate-12 transition-transform" />
            <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
         </div>
         <div className="flex-1 flex flex-col gap-6">
            {[
                { id: 'dashboard', icon: LayoutDashboard, label: '数据仓库' },
                { id: 'analytics', icon: PieChart, label: '科研可视化' },
                { id: 'ai', icon: Bot, label: 'AI 实验室' }
            ].map((btn) => (
                <button key={btn.id} onClick={() => setActiveView(btn.id as AppView)} className={`w-12 h-12 rounded-2xl transition-all duration-300 relative group flex items-center justify-center ${activeView === btn.id ? 'bg-primary-600 text-white shadow-lg shadow-primary-500/20 scale-105' : 'text-slate-500 hover:text-primary-400 hover:bg-slate-800'}`} title={btn.label}>
                    <btn.icon size={22} />
                    {activeView === btn.id && <div className="absolute -left-3 top-1/2 -translate-y-1/2 w-1.5 h-8 bg-primary-400 rounded-r-full"></div>}
                </button>
            ))}
         </div>
         <div className="flex flex-col gap-4 mb-2">
            <button onClick={() => setIsAdminOpen(true)} className="w-12 h-12 flex items-center justify-center text-slate-500 hover:text-amber-400 hover:bg-slate-800 rounded-2xl transition-all"><ShieldCheck size={22} /></button>
         </div>
      </nav>

      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <div className="shrink-0 z-[60] relative">
            <TopBar 
                user={currentUser} onLogout={handleLogout} onOpenProfile={() => setIsProfileOpen(true)} onOpenAdmin={() => setIsAdminOpen(true)} 
                searchQuery={searchQuery} onSearchChange={setSearchQuery} onAiSearch={handleAiSearch} columns={columns} onToggleColumn={handleToggleColumn} onToggleAllColumns={handleToggleAllColumns} 
                onOpenImport={() => setIsImportOpen(true)} onExport={handleExport} isExporting={isExporting} viewMode={activeView === 'analytics' ? 'chart' : 'grid'} 
                onViewModeChange={(m) => setActiveView(m === 'chart' ? 'analytics' : 'dashboard')} showAdvancedFilters={showFilters} onToggleFilters={() => setShowFilters(!showFilters)} activeFilterCount={Object.keys(numericFilters).length}
            />
        </div>

        <div className="flex-1 flex overflow-hidden">
            {(activeView === 'dashboard' || activeView === 'analytics') && (
                <div className="w-72 shrink-0 border-r border-slate-200 dark:border-slate-800 bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm flex flex-col">
                    <TreeSidebar 
                        categories={CATEGORY_TREE} 
                        selectedCategoryIds={selectedCategoryIds} 
                        onToggleCategory={toggleCategory} 
                        onClearCategories={() => setSelectedCategoryIds(new Set())}
                        totalCount={allProducts.length} 
                        counts={categoryCounts} 
                    />
                </div>
            )}

            <div className="flex-1 flex flex-col p-6 min-h-0 relative">
                <div className="flex-1 w-full min-h-0 relative animate-in fade-in duration-500">
                    {activeView === 'dashboard' && (
                        <div className="absolute inset-0 bg-white/40 dark:bg-slate-950/20 border border-white/20 dark:border-slate-800 rounded-[2.5rem] shadow-inner overflow-hidden">
                            <DataGrid 
                                data={filteredData} 
                                columns={columns} 
                                isLoading={false} 
                                onDelete={handleDelete} 
                                onUpdate={(p) => { setAllProducts(prev => prev.map(old => old.id === p.id ? p : old)); addToast('success', '牌号物性已更新'); }} 
                                onBatchUpdate={(ids, u) => { setAllProducts(prev => prev.map(p => ids.includes(p.id) ? {...p, ...u} : p)); addToast('success', '批量更新完成'); }} 
                                onCategorySelect={selectSingleCategory} 
                                onViewDetails={setViewingProduct}
                                selectedIds={selectedIds} 
