                                    <div className="p-3 bg-primary-600 rounded-2xl text-white shadow-lg shadow-primary-500/20"><Bot size={24} /></div>
                                    <div><h2 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">ResinAI Lab</h2><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><Sparkles size={10} className="text-primary-500" /> Deep Scientific Engine Active</p></div>
                                </div>
                             </div>
                             <div className="flex-1 relative bg-slate-50/30 dark:bg-transparent overflow-hidden"><AIAssistant contextData={aiContextData} inlineView={true} onGradeClick={handleAIGradeClick} onNavigateToChart={() => setActiveView('analytics')} initialPrompt={aiPrompt} /></div>
                        </div>
                    )}
                </div>
            </div>
        </div>

        {selectedIds.size > 0 && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[80] animate-in slide-in-from-bottom-10 duration-500 pointer-events-none">
                <div className="pointer-events-auto bg-slate-900/90 dark:bg-white/90 backdrop-blur-2xl px-6 py-4 rounded-[2.5rem] border border-white/10 dark:border-slate-200 shadow-2xl flex items-center gap-6">
                    <div className="flex items-center gap-3 pr-6 border-r border-white/10 dark:border-slate-200">
                        <div className="w-10 h-10 bg-primary-600 rounded-full flex items-center justify-center text-white font-black text-sm shadow-glow">{selectedIds.size}</div>
                        <div><p className="text-xs font-black text-white dark:text-slate-900 uppercase tracking-widest">{t('selected')}</p><p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-tighter">项记录已入选</p></div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={handleAiAnalysis} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-2xl text-white shadow-lg shadow-indigo-500/30 hover:scale-110 transition-all active:scale-95">
                                <Sparkles size={20} />
                            </div>
                            <span className="text-[9px] font-bold text-indigo-400 dark:text-indigo-600 uppercase tracking-tighter">AI 洞察</span>
                        </button>

                        <button onClick={() => setIsComparisonOpen(true)} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-slate-100 rounded-2xl text-white dark:text-slate-700 hover:bg-emerald-500 hover:text-white transition-all group-hover:scale-110 active:scale-95"><GitCompare size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-tighter">对比分析</span>
                        </button>

                        <button onClick={handleExport} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-slate-100 rounded-2xl text-white dark:text-slate-700 hover:bg-primary-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Download size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-tighter">生成报告</span>
                        </button>
                        <button onClick={() => handleDelete(Array.from(selectedIds))} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-rose-100 rounded-2xl text-white dark:text-rose-700 hover:bg-rose-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Trash2 size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-tighter">{t('delete')}</span>
                        </button>
                    </div>
                </div>
            </div>
        )}
      </div>

      <ImportModal isOpen={isImportOpen} onClose={() => setIsImportOpen(false)} onImport={handleImportData} />
      <ProfileModal isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} user={currentUser} onSave={handleUpdateUserProfile} />
      <AdminModal isOpen={isAdminOpen} onClose={() => setIsAdminOpen(false)} />
      {activeView !== 'ai' && <AIAssistant contextData={aiContextData} />}
      <ProductDetailDrawer product={viewingProduct} onClose={() => setViewingProduct(null)} onCategoryClick={selectSingleCategory} />
      {isComparisonOpen && <ComparisonView products={productsToCompare} onClose={() => setIsComparisonOpen(false)} onRemoveProduct={(id) => { const next = new Set(selectedIds); next.delete(id); setSelectedIds(next); if(next.size === 0) setIsComparisonOpen(false); }} />}
    </div>
  );
};

const App: React.FC = () => (<LanguageProvider><ThemeProvider><AppContent /></ThemeProvider></LanguageProvider>);
