// --- Toast Component ---
interface Toast { id: string; type: 'success' | 'error' | 'info'; message: string; }
const ToastContainer: React.FC<{ toasts: Toast[], removeToast: (id: string) => void }> = ({ toasts, removeToast }) => (
    <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] flex flex-col gap-2 pointer-events-none">
        {toasts.map(t => (
            <div key={t.id} className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-2xl shadow-2xl animate-in slide-in-from-top-5 fade-in duration-300 border backdrop-blur-md ${
