            </div>
        ))}
    </div>
);

const getDynamicColumns = (products: Product[]): ColumnConfig[] => {
  const propertyKeys = new Set<string>();
  products.forEach(p => { Object.keys(p.properties).forEach(k => propertyKeys.add(k)); });
  const defaultVisible = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '典型应用'];
  const dynamicCols: ColumnConfig[] = Array.from(propertyKeys).map(key => ({
    key, label: key, visible: defaultVisible.includes(key), isSystem: false
  })).sort((a, b) => {
      const aIsLikelyImportant = defaultVisible.includes(a.key);
      const bIsLikelyImportant = defaultVisible.includes(b.key);
      if (aIsLikelyImportant && !bIsLikelyImportant) return -1;
      if (!aIsLikelyImportant && bIsLikelyImportant) return 1;
      return a.label.localeCompare(b.label);
  });
  return [
    { key: 'gradeName', label: '牌号', visible: true, isSystem: true },
    { key: 'manufacturer', label: '生产厂家', visible: true, isSystem: true },
    ...dynamicCols
  ];
};

type AppView = 'dashboard' | 'analytics' | 'ai';

const AppContent: React.FC = () => {
  const { t, tProp, language } = useLanguage();
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('resindb-session');
    return saved ? JSON.parse(saved) : null;
  });

  const [toasts, setToasts] = useState<Toast[]>([]);
  const addToast = useCallback((type: Toast['type'], message: string) => {
      const id = Date.now().toString();
      setToasts(prev => [...prev, { id, type, message }]);
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  }, []);

  const [allProducts, setAllProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<Set<string>>(new Set());

  const [searchQuery, setSearchQuery] = useState('');
  const [columns, setColumns] = useState<ColumnConfig[]>([]);
  const [isImportOpen, setIsImportOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [activeView, setActiveView] = useState<AppView>('dashboard');
  const [isExporting, setIsExporting] = useState(false);
  const [isComparisonOpen, setIsComparisonOpen] = useState(false);

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [showFilters, setShowFilters] = useState(false);
  const [numericFilters, setNumericFilters] = useState<Record<string, { min: string; max: string }>>({});

  const [aiPrompt, setAiPrompt] = useState<string | undefined>(undefined);

  useEffect(() => { setColumns(getDynamicColumns(allProducts)); }, [allProducts]);

  const categoryCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    allProducts.forEach(product => {
        const cats = Array.isArray(product.categoryIds) ? product.categoryIds : [];
        cats.forEach(catId => {
            counts[catId] = (counts[catId] || 0) + 1;
        });
    });
    return counts;
  }, [allProducts]);

  // Helper to find category name map
  const categoryNameMap = useMemo(() => {
      const map = new Map<string, string>();
      const traverse = (cats: Category[]) => {
          cats.forEach(c => {
              map.set(c.id, language === 'en' && c.nameEn ? c.nameEn : c.name);
              if (c.children) traverse(c.children);
          });
      };
      traverse(CATEGORY_TREE);
      return map;
  }, [language]);

  const resolvePropKey = useCallback((label: string): string | null => {
      const cleanLabel = label.toLowerCase();
      const directMatch = columns.find(c => c.key.toLowerCase() === cleanLabel || tProp(c.label).toLowerCase() === cleanLabel);
      if (directMatch) return directMatch.key;
      const reverseKey = Object.keys(propertyMap).find(k => k.toLowerCase() === cleanLabel || propertyMap[k].toLowerCase() === cleanLabel);
      if (reverseKey) return reverseKey;
      return null;
  }, [columns, tProp]);

  const filteredData = useMemo(() => {
    const syntaxRegex = /([\u4e00-\u9fa5\w]+):([<>]=?|[-.0-9a-zA-Z]+)/g;
    const syntaxFilters: { key: string, operator: string, value: string | number, max?: number }[] = [];
    let processedQuery = searchQuery;
    let match;
    while ((match = syntaxRegex.exec(searchQuery)) !== null) {
        const [full, label, condition] = match;
        const key = resolvePropKey(label);
        if (key) {
            processedQuery = processedQuery.replace(full, '');
            if (condition.includes('-') && !condition.startsWith('-')) {
                const parts = condition.split('-');
                syntaxFilters.push({ key, operator: 'range', value: parseFloat(parts[0]), max: parseFloat(parts[1]) });
            } else if (condition.match(/^[<>]=?/)) {
                const op = condition.match(/^[<>]=?/)?.[0] || '';
                const val = parseFloat(condition.replace(op, ''));
                syntaxFilters.push({ key, operator: op, value: val });
            } else {
                const numVal = parseFloat(condition);
                syntaxFilters.push({ key, operator: '=', value: isNaN(numVal) ? condition : numVal });
            }
        }
    }
    const textKeywords = processedQuery.toLowerCase().split(' ').filter(k => k.trim());
    return allProducts.filter(product => {
      // Logic Update: Multi-select filtering with robust handling for empty/null categoryIds
      if (selectedCategoryIds.size > 0) {
          const pCats = Array.isArray(product.categoryIds) ? product.categoryIds : [];
          const hasMatch = pCats.some(id => selectedCategoryIds.has(id));
          if (!hasMatch) return false;
      }

      const matchesText = textKeywords.every(query => product.gradeName.toLowerCase().includes(query) || product.manufacturer.toLowerCase().includes(query) || Object.keys(product.properties).some(k => k.toLowerCase().includes(query)));
      if (!matchesText) return false;
      const matchesSyntax = syntaxFilters.every(f => {
          const propVal = product.properties[f.key]?.value;
          const val = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(val) || typeof f.value === 'string') return String(propVal).toLowerCase().includes(String(f.value).toLowerCase());
          switch(f.operator) {
              case '>': return val > (f.value as number);
              case '<': return val < (f.value as number);
              case '>=': return val >= (f.value as number);
              case '<=': return val <= (f.value as number);
              case 'range': return val >= (f.value as number) && val <= (f.max || Infinity);
              case '=': return val === (f.value as number);
              default: return true;
          }
      });
      if (!matchesSyntax) return false;
      return Object.entries(numericFilters).every(([key, range]) => {
          const propVal = product.properties[key]?.value;
          const num = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(num)) return true;
          const min = range.min === '' ? -Infinity : parseFloat(range.min);
          const max = range.max === '' ? Infinity : parseFloat(range.max);
          return num >= min && num <= max;
      });
    });
  }, [allProducts, selectedCategoryIds, searchQuery, numericFilters, resolvePropKey]);

  const handleLogin = (user: User) => { setCurrentUser(user); localStorage.setItem('resindb-session', JSON.stringify(user)); };
  const handleLogout = () => { setCurrentUser(null); localStorage.removeItem('resindb-session'); };
  const handleToggleColumn = (key: string) => { setColumns(cols => cols.map(c => c.key === key ? { ...c, visible: !c.visible } : c)); };
  const handleToggleAllColumns = (visible: boolean) => { setColumns(cols => cols.map(c => c.isSystem ? c : { ...c, visible })); };

  const handleExport = async () => { setIsExporting(true); await new Promise(r => setTimeout(r, 800)); addToast('success', '分析报告已生成'); setIsExporting(false); };
  const handleDelete = (ids: string[]) => { setAllProducts(prev => prev.filter(p => !ids.includes(p.id))); setSelectedIds(new Set()); addToast('success', `已同步删除 ${ids.length} 条记录`); };

  const handleImportData = (newProducts: Product[]) => { 
      setAllProducts(prev => [...newProducts, ...prev]); 
      setIsImportOpen(false); 
      addToast('success', `${newProducts.length} 条数据入库成功`); 
