  const selectSingleCategory = (id: string) => {
      setSelectedCategoryIds(new Set([id]));
  };

  const productsToCompare = useMemo(() => {
      return allProducts.filter(p => selectedIds.has(p.id));
  }, [allProducts, selectedIds]);

  const activeFilters = useMemo<FilterItem[]>(() => {
      const items: FilterItem[] = [];
      if (searchQuery.trim()) {
