                                </div>
                             </div>
                             <div className="flex-1 relative bg-slate-50/30 dark:bg-transparent overflow-hidden"><AIAssistant contextData={aiContextData} inlineView={true} onGradeClick={handleAIGradeClick} onNavigateToChart={() => setActiveView('analytics')} initialPrompt={aiPrompt} /></div>
