const ChartSuggestion: React.FC<{ type: string, onClick: () => void }> = ({ type, onClick }) => {
    return (
        <button 
            onClick={onClick}
            className="flex items-center gap-2 px-3 py-1.5 bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 rounded-lg border border-primary-200 dark:border-primary-800 hover:bg-primary-100 transition-all text-[10px] font-bold uppercase tracking-wider group"
        >
