  const chatContainerRef = useRef<HTMLDivElement>(null);

  const quickPrompts = useMemo(() => {
      const base = ['预测加工流动性', '检索高冲击牌号', '分析刚韧平衡'];
      if (contextData.length > 0) {
          if (contextData.length < 5) return ['对比这几个牌号的差异', '生成这些牌号的物性报告', ...base];
          return ['分析当前筛选结果的分布规律', '找出其中流动性最好的牌号', ...base];
      }
      return base;
  }, [contextData]);

  useEffect(() => {
    if (messages.length === 0) {
        setMessages([{ 
            id: 'welcome', 
            role: 'model', 
            text: t('welcomeMessage') 
        }]);
    }
  }, [t]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, isOpen]);

  const saveConfig = (newConfig: ApiConfig) => {
      setApiConfig(newConfig);
      localStorage.setItem('resindb-api-config', JSON.stringify(newConfig));
      setShowSettings(false);
  };

  const filteredMessages = useMemo(() => {
    if (!searchQuery.trim()) return messages;
    return messages.filter(m => m.text.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [messages, searchQuery]);

  const handleSendMessage = async (customInput?: string) => {
    const textToSend = customInput || input;
    if ((!textToSend.trim() && !attachedImage) || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: attachedImage || undefined
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setAttachedImage(null);
    setIsLoading(true);
    if(searchQuery) {
        setSearchQuery('');
        setIsSearchOpen(false);
    }

    // Prepare Context string
    let contextStr = "";
    if (contextData.length > 0) {
        contextStr = JSON.stringify(contextData.slice(0, 20).map(p => ({
            grade: p.gradeName,
            manufacturer: p.manufacturer,
            mfr: p.properties['熔体质量流动速率']?.value,
            density: p.properties['密度']?.value,
            flex: p.properties['弯曲模量']?.value,
            impact: p.properties['悬臂梁缺口冲击强度']?.value,
            app: p.properties['典型应用']?.value
        })));
    }

    const systemPromptText = "You are ResinAI. A senior materials scientist at PetroChina Research Institute. Analyze data specifically. Wrap grade names in **double asterisks** like **HDPE 5000S**. Suggest using specific charts if appropriate (Ashby, Radar, GPC)." + 
        (userMsg.image ? "\nFocus on image-based QC analysis." : "") + 
        (contextStr ? `\n[Experimental Context]: ${contextStr}` : "");

    try {
      let responseText = "";

      if (apiConfig.provider === 'gemini') {
          // --- Google Gemini Logic ---
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const parts: any[] = [];

          if (userMsg.image) {
             const base64Data = userMsg.image.split(',')[1];
             const mimeType = userMsg.image.split(';')[0].split(':')[1] || 'image/jpeg';
             parts.push({ inlineData: { mimeType, data: base64Data } });
          }
          parts.push({ text: userMsg.text });
          if (contextStr) parts.push({ text: `\nData: ${contextStr}` });

          const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: [{ role: 'user', parts: parts }],
            config: {
                systemInstruction: systemPromptText,
                thinkingConfig: useThinking ? { thinkingBudget: 2048 } : undefined,
            }
          });
          responseText = response.text || "Analysis result empty.";

      } else {
          // --- OpenAI Compatible Logic ---
          if (!apiConfig.apiKey) throw new Error("API Key Missing");

          const openaiMessages: any[] = [
              { role: "system", content: systemPromptText }
          ];

          let contentPayload: any = userMsg.text;

          if (userMsg.image) {
              contentPayload = [
                  { type: "text", text: userMsg.text },
                  { type: "image_url", image_url: { url: userMsg.image } }
              ];
          }

          openaiMessages.push({ role: "user", content: contentPayload });

          const response = await fetch(`${apiConfig.baseUrl}/chat/completions`, {
              method: 'POST',
              headers: {
                  'Content-Type': 'application/json',
                  'Authorization': `Bearer ${apiConfig.apiKey}`
              },
              body: JSON.stringify({
                  model: apiConfig.model || 'deepseek-chat', 
                  messages: openaiMessages,
                  temperature: 0.7,
                  max_tokens: 2048
              })
          });

          if (!response.ok) {
              const err = await response.text();
              throw new Error(`API ${response.status}: ${err}`);
          }

          const data = await response.json();
          responseText = data.choices?.[0]?.message?.content || "No response content.";
      }

      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: responseText
      }]);

    } catch (error: any) {
      console.error("AI Error:", error);

      let friendlyMsg = "I'm having trouble processing that request.";
      let errorType: Message['errorType'] = 'generic';

      if (error.message.includes('API Key') || error.message.includes('401') || error.message.includes('403')) {
          friendlyMsg = "It looks like my access credentials (API Key) are missing or invalid. Please check the settings.";
          errorType = 'auth';
      } else if (error.message.includes('fetch') || error.message.includes('Network') || error.message.includes('503')) {
          friendlyMsg = "I can't reach the data center right now. Please check your internet connection.";
          errorType = 'network';
      }

      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'system',
        text: friendlyMsg,
        errorType: errorType
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
      // Trigger if new prompt is provided and different from last processed one
      if (initialPrompt && initialPrompt !== lastProcessedPromptRef.current && !isLoading) {
          handleSendMessage(initialPrompt);
          lastProcessedPromptRef.current = initialPrompt;
      }
  }, [initialPrompt]);

  const renderInput = () => (
    <div className="flex items-end gap-2 bg-slate-100 dark:bg-slate-800/50 p-2 rounded-[2rem] border border-slate-200 dark:border-slate-700 focus-within:ring-4 focus-within:ring-primary-500/10 focus-within:border-primary-500 transition-all shadow-inner relative">
        <input type="file" ref={fileInputRef} accept="image/*" className="hidden" onChange={(e) => {
            const f = e.target.files?.[0];
            if(f){ const r = new FileReader(); r.onloadend = () => setAttachedImage(r.result as string); r.readAsDataURL(f); }
        }} />
        <button 
