  }, [initialChartType]);

  // Filter State
  const [filters, setFilters] = useState<Record<string, { min: string; max: string }>>({});
  const [isFilterDropdownOpen, setIsFilterDropdownOpen] = useState(false);
  const filterDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (filterDropdownRef.current && !filterDropdownRef.current.contains(event.target as Node)) {
              setIsFilterDropdownOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Determine base data set
  const baseData = useMemo(() => {
    return (selectedProducts && selectedProducts.length > 0) ? selectedProducts : data;
  }, [data, selectedProducts]);

  // Extract available numeric properties for filtering - Memoized to prevent heavy loop on every render
  const numericProperties = useMemo(() => {
      if (!baseData) return [];
      const props = new Set<string>();
      baseData.forEach(p => {
          Object.entries(p.properties).forEach(([key, val]) => {
              const num = parseFloat(String(val.value));
              if (!isNaN(num)) props.add(key);
          });
      });
      return Array.from(props).sort();
  }, [baseData]);

  // Apply filters to baseData
  const filteredData = useMemo(() => {
      if (!baseData) return [];
      if (Object.keys(filters).length === 0) return baseData;

      return baseData.filter(p => {
          return Object.entries(filters).every(([key, { min, max }]) => {
              const val = p.properties[key]?.value;
              const numVal = parseFloat(String(val));

              if (isNaN(numVal)) return false; 

              const minVal = min === '' ? -Infinity : parseFloat(min);
              const maxVal = max === '' ? Infinity : parseFloat(max);

              return numVal >= minVal && numVal <= maxVal;
          });
      });
  }, [baseData, filters]);

  // Helper: Safe Float Parser (Layer 1: Anti-Crash)
  const safeParse = (val: any, fallback = 0): number => {
      if (val === undefined || val === null || val === '') return fallback;
      const num = parseFloat(String(val));
      return isNaN(num) ? fallback : num;
  };

  const handleAddFilter = (key: string) => {
      if (!filters[key]) {
          setFilters(prev => ({ ...prev, [key]: { min: '', max: '' } }));
      }
      setIsFilterDropdownOpen(false);
  };

  const updateFilter = (key: string, field: 'min' | 'max', val: string) => {
      // Allow only numbers and decimals
      if (val && !/^-?\d*\.?\d*$/.test(val)) return;
      setFilters(prev => ({
          ...prev,
          [key]: { ...prev[key], [field]: val }
      }));
  };

  const removeFilter = (key: string) => {
      setFilters(prev => {
          const next = { ...prev };
          delete next[key];
          return next;
      });
  };

  // --- Data Preparation Logic (Defensive) using filteredData ---

  // 1. Radar Data: Compare top 5 (or selected) products
  const radarData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const source = filteredData.slice(0, 5); 
        return source.map(p => ({
          name: p.gradeName,
          value: [
            safeParse(p.properties['熔体质量流动速率']?.value),
            safeParse(p.properties['密度']?.value),
            safeParse(p.properties['弯曲模量']?.value),
            safeParse(p.properties['拉伸屈服应力']?.value),
            safeParse(p.properties['悬臂梁缺口冲击强度']?.value)
          ]
        }));
    } catch (e) {
        console.error("Radar Prep Error:", e);
        return [];
    }
  }, [filteredData]);

  // 2. Ashby Data: MFR vs Impact
  const ashbyData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const groups: Record<string, any[]> = {};
        filteredData.forEach(p => {
          const man = p.manufacturer || 'Unknown';
          if (!groups[man]) groups[man] = [];

          const mfr = safeParse(p.properties['熔体质量流动速率']?.value, -1);
          const impact = safeParse(p.properties['悬臂梁缺口冲击强度']?.value, -1);

          if (mfr > 0 && impact > 0) {
            groups[man].push([mfr, impact, p.gradeName]);
          }
        });

        return Object.entries(groups).map(([name, points]) => ({
          name,
          data: points
        }));
    } catch(e) {
        console.error("Ashby Prep Error:", e);
        return [];
    }
  }, [filteredData]);

  // 3. MFR vs Density Data
  const mfrDensityData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const groups: Record<string, any[]> = {};
        filteredData.forEach(p => {
          const man = p.manufacturer || 'Unknown';
          if (!groups[man]) groups[man] = [];

          const mfr = safeParse(p.properties['熔体质量流动速率']?.value, -1);
          const density = safeParse(p.properties['密度']?.value, -1);

          if (mfr > 0 && density > 0) {
            groups[man].push([mfr, density, p.gradeName]);
          }
        });

        return Object.entries(groups).map(([name, points]) => ({
          name,
          data: points
        }));
    } catch(e) {
        console.error("MFR-Density Prep Error:", e);
        return [];
    }
  }, [filteredData]);

  // 5. Ternary Data: Mock Formulation (Simulated based on properties)
  const ternaryData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const source = filteredData.length > 0 ? filteredData : [];
        return source.slice(0, 100).map((p, i) => {
            // Simulation logic to create 3 clusters based on density/MFR
            const mfr = safeParse(p.properties['熔体质量流动速率']?.value, 1);
            let a, b, c;

            if (mfr < 1) {
                a = 0.6 + Math.random() * 0.3;
                b = Math.random() * (0.9 - a);
                c = 1 - a - b;
            } else if (mfr > 10) {
                b = 0.6 + Math.random() * 0.3;
                a = Math.random() * (0.9 - b);
                c = 1 - a - b;
            } else {
                c = 0.5 + Math.random() * 0.4;
                a = Math.random() * (0.9 - c);
                b = 1 - a - c;
            }

            const sum = a + b + c;
            a = a / sum;
            b = b / sum;
            c = c / sum;

            return {
                a, b, c,
                name: p.gradeName,
                value: safeParse(p.properties['拉伸强度']?.value, 50) + (Math.random() * 10 - 5)
            };
        });
    } catch(e) {
        return [];
    }
  }, [filteredData]);

  // Select the correct data based on chart type to pass to ScientificChart
  const currentChartData = useMemo(() => {
      switch(activeChart) {
          case 'radar': return radarData;
          case 'ashby': return ashbyData;
          case 'mfr_density': return mfrDensityData;
          case 'gpc': return filteredData; 
          case 'rheology': return { products: filteredData, temps: selectedRheologyTemps }; 
          case 'ternary': return ternaryData;
          default: return [];
      }
  }, [activeChart, radarData, ashbyData, mfrDensityData, filteredData, ternaryData, selectedRheologyTemps]);

  const handleExport = async (format: 'png' | 'json') => {
      setIsExporting(true);
      if (format === 'png' && chartInstance) {
          try {
            const dataUrl = chartInstance.getDataURL({
                type: 'png',
                pixelRatio: 2,
                backgroundColor: '#fff'
            });
            const a = document.createElement('a');
            a.href = dataUrl;
            a.download = `resindb_${activeChart}_analysis.png`;
            a.click();
          } catch(e) { console.error(e); }
      } else if (format === 'json') {
          const jsonStr = JSON.stringify(currentChartData, null, 2);
          const blob = new Blob([jsonStr], {type: 'application/json'});
          const url = URL.createObjectURL(blob);
          const a = document.createElement('a');
          a.href = url;
          a.download = `resindb_${activeChart}_data.json`;
          a.click();
      }
      setIsExporting(false);
  };

  const chartDescriptions = {
      radar: t('desc_radar'),
      ashby: t('desc_ashby'),
      mfr_density: t('desc_mfr_density'),
      gpc: t('desc_gpc'),
      rheology: t('desc_rheology'),
      ternary: t('desc_ternary')
  };

  const toggleRheologyTemp = (temp: number) => {
    setSelectedRheologyTemps(prev => 
      prev.includes(temp) 
        ? prev.filter(t => t !== temp) 
        : [...prev, temp].sort()
    );
  };

  // Check if we have valid data for the current view to show improved empty state
  const hasValidData = filteredData.length > 0 && currentChartData && (Array.isArray(currentChartData) ? currentChartData.length > 0 : true);

  return (
    <div className="flex flex-col md:flex-row h-full gap-4 overflow-hidden">
      {/* Scientific Controls Sidebar */}
      <div className={`flex flex-col bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl transition-all duration-500 ease-out shrink-0 overflow-hidden shadow-xl ${showConfig ? 'w-full md:w-72 opacity-100 translate-x-0' : 'w-0 opacity-0 -translate-x-10 border-0 pointer-events-none'}`}>
        <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50/80 dark:bg-slate-950/50 backdrop-blur-sm">
          <div className="flex items-center gap-2 font-black text-sm text-slate-800 dark:text-white uppercase tracking-widest">
            <Activity size={16} className="text-emerald-500" />
            {t('analysisMode')}
          </div>
          <button onClick={() => setShowConfig(false)} className="md:hidden text-slate-400 hover:text-slate-600">
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
            <div className="p-4 space-y-2">
                {[
                    { id: 'radar', label: t('chart_radar'), icon: Hexagon, color: 'text-indigo-500' },
                    { id: 'ashby', label: t('chart_ashby'), icon: ScatterChart, color: 'text-rose-500' },
                    { id: 'mfr_density', label: t('chart_mfr_density'), icon: Target, color: 'text-sky-500' },
                    { id: 'gpc', label: t('chart_gpc'), icon: Waves, color: 'text-blue-500' },
                    { id: 'rheology', label: t('chart_rheology'), icon: Activity, color: 'text-amber-500' },
                    { id: 'ternary', label: t('chart_ternary'), icon: Triangle, color: 'text-emerald-500' },
                ].map(item => (
                    <button 
                        key={item.id}
                        onClick={() => setActiveChart(item.id as ChartType)}
                        className={`w-full flex items-center gap-3 p-3 rounded-2xl border transition-all duration-200 group relative overflow-hidden ${
                            activeChart === item.id 
                            ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900 border-transparent shadow-lg' 
                            : 'bg-white dark:bg-slate-800/50 border-slate-100 dark:border-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'
                        }`}
                    >
                        <div className={`p-2 rounded-xl bg-slate-100 dark:bg-slate-700/50 ${activeChart === item.id ? 'bg-white/20 text-white' : item.color}`}>
                            <item.icon size={18} />
                        </div>
                        <span className="text-xs font-bold uppercase tracking-wide">{item.label}</span>
                        {activeChart === item.id && <div className="absolute right-0 top-0 bottom-0 w-1 bg-emerald-500"></div>}
                    </button>
                ))}
            </div>

            {/* --- Rheology Specific Settings --- */}
            {activeChart === 'rheology' && filteredData.length === 1 && (
                <div className="px-4 pb-4 animate-in slide-in-from-left-2 fade-in duration-300">
                    <div className="border-t border-slate-100 dark:border-slate-800 pt-4 mb-3">
                        <div className="flex items-center gap-2 font-black text-sm text-slate-800 dark:text-white uppercase tracking-widest mb-3">
                            <Thermometer size={16} className="text-amber-500" />
                            温度曲线 (Temps)
                        </div>
                        <div className="space-y-2">
                            {[190, 210, 230].map(temp => (
                                <button
                                    key={temp}
                                    onClick={() => toggleRheologyTemp(temp)}
                                    className={`w-full flex items-center justify-between px-3 py-2 rounded-xl border transition-all ${
                                        selectedRheologyTemps.includes(temp)
                                        ? 'bg-amber-50 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800 text-amber-700 dark:text-amber-400 shadow-sm'
                                        : 'bg-white dark:bg-slate-800/50 border-slate-100 dark:border-slate-800 text-slate-400 hover:border-amber-200/50'
                                    }`}
                                >
                                    <span className="text-xs font-bold">{temp}°C</span>
                                    {selectedRheologyTemps.includes(temp) && <Check size={14} />}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {/* --- Data Filters Section --- */}
            <div className="px-4 pb-4">
                <div className="border-t border-slate-100 dark:border-slate-800 pt-4 mb-3 flex items-center justify-between">
                    <div className="flex items-center gap-2 font-black text-sm text-slate-800 dark:text-white uppercase tracking-widest">
                        <Filter size={16} className="text-blue-500" />
                        {t('dataFilters')}
                    </div>

                    <div className="relative" ref={filterDropdownRef}>
                        <button 
                            onClick={() => setIsFilterDropdownOpen(!isFilterDropdownOpen)}
                            className="p-1.5 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded-lg hover:bg-blue-100 dark:hover:bg-blue-900/40 transition-colors"
                            title="Add Filter"
                        >
                            <Plus size={16} />
                        </button>

                        {isFilterDropdownOpen && (
                            <div className="absolute top-full right-0 mt-2 w-56 max-h-60 overflow-y-auto custom-scrollbar bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-xl z-50 p-1">
                                {numericProperties.length > 0 ? numericProperties.map(prop => (
                                    <button
                                        key={prop}
                                        onClick={() => handleAddFilter(prop)}
                                        className="w-full text-left px-3 py-2 text-xs font-medium text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 rounded-lg transition-colors truncate"
                                        disabled={!!filters[prop]}
                                    >
                                        <div className="flex items-center justify-between">
                                            <span className="truncate">{tProp(prop)}</span>
                                            {filters[prop] && <Check size={12} className="text-emerald-500 shrink-0" />}
                                        </div>
                                    </button>
                                )) : <div className="p-3 text-xs text-slate-400 text-center">No numeric properties found in dataset</div>}
                            </div>
                        )}
                    </div>
                </div>

                <div className="space-y-3">
                    {Object.keys(filters).length === 0 ? (
                        <div className="p-4 rounded-2xl bg-slate-50 dark:bg-slate-900/30 border border-slate-100 dark:border-slate-800 border-dashed text-center">
                            <span className="text-xs text-slate-400">{t('noFilters')}</span>
                        </div>
                    ) : (
                        Object.entries(filters).map(([key, { min, max }]) => (
                            <div key={key} className="bg-white dark:bg-slate-800/50 p-3 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm animate-in slide-in-from-right-2 fade-in duration-300">
                                <div className="flex justify-between items-center mb-2.5">
                                    <span className="text-xs font-bold text-slate-700 dark:text-slate-200 truncate" title={tProp(key)}>{tProp(key)}</span>
                                    <button 
                                        onClick={() => removeFilter(key)}
                                        className="text-slate-400 hover:text-rose-500 transition-colors p-1"
                                    >
                                        <X size={12} />
                                    </button>
                                </div>
                                <div className="flex items-center gap-2">
                                    <div className="flex-1 relative">
                                        <input 
                                            type="text" 
                                            placeholder="Min" 
                                            value={min}
                                            onChange={(e) => updateFilter(key, 'min', e.target.value)}
                                            className="w-full px-2 py-1.5 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs font-mono outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-500/10 transition-all text-center"
                                        />
                                    </div>
                                    <span className="text-slate-300 dark:text-slate-600 font-light">—</span>
                                    <div className="flex-1 relative">
                                        <input 
                                            type="text" 
                                            placeholder="Max" 
                                            value={max}
                                            onChange={(e) => updateFilter(key, 'max', e.target.value)}
                                            className="w-full px-2 py-1.5 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs font-mono outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-500/10 transition-all text-center"
                                        />
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>

            <div className="mx-4 mt-2 mb-6 p-4 bg-slate-50 dark:bg-slate-950/30 rounded-2xl border border-slate-100 dark:border-slate-800">
                <div className="flex items-center gap-2 mb-2 text-slate-400 dark:text-slate-500">
                    <Info size={14} />
                    <span className="text-[10px] font-bold uppercase tracking-widest">{t('chartContext')}</span>
                </div>
                <p className="text-xs text-slate-600 dark:text-slate-300 leading-relaxed font-medium">
                    {chartDescriptions[activeChart]}
                </p>
                <div className="mt-3 pt-3 border-t border-slate-200/50 dark:border-slate-800/50 flex items-center justify-between text-[10px]">
                    <span className="text-slate-400 font-bold uppercase tracking-wider">Active Dataset</span>
                    <span className="text-blue-600 dark:text-blue-400 font-black bg-blue-50 dark:bg-blue-900/20 px-2 py-0.5 rounded-full">{filteredData.length} Items</span>
                </div>
            </div>
        </div>

        <div className="p-4 border-t border-slate-100 dark:border-slate-800 grid grid-cols-2 gap-3 bg-white dark:bg-slate-900 shrink-0">
            <button onClick={() => handleExport('json')} disabled={!hasValidData} className="flex items-center justify-center gap-2 p-3 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-xl text-[10px] font-bold text-slate-600 dark:text-slate-300 transition-colors uppercase tracking-wider disabled:opacity-50 disabled:cursor-not-allowed"><FileJson size={14} /> {t('exportJson')}</button>
            <button onClick={() => handleExport('png')} disabled={isExporting || !hasValidData} className="flex items-center justify-center gap-2 p-3 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-xl text-[10px] font-bold transition-all uppercase tracking-wider shadow-lg">{isExporting ? <Loader2 size={14} className="animate-spin" /> : <ImageIcon size={14} />} {t('exportPng')}</button>
        </div>
      </div>

      {/* Chart Canvas Area */}
      <div className="flex-1 flex flex-col bg-white/50 dark:bg-slate-900/50 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-[2rem] relative min-h-[500px] shadow-2xl overflow-hidden group">
         {!showConfig && (
             <button onClick={() => setShowConfig(true)} className="absolute top-6 right-6 z-30 p-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-slate-500 hover:text-emerald-500 shadow-xl transition-all hover:scale-105 active:scale-95">
                <Settings size={20} />
             </button>
         )}

         <div className="flex-1 w-full h-full p-4 relative">
            <ScientificChart 
                type={activeChart} 
                data={currentChartData} 
                onChartReady={setChartInstance}
                loading={false}
            />

            {/* Watermark */}
            <div className="absolute bottom-6 right-6 pointer-events-none opacity-10 flex flex-col items-end z-0">
                <span className="text-4xl font-black text-slate-900 dark:text-white tracking-tighter">ResinDB</span>
                <span className="text-xs font-bold uppercase tracking-widest text-slate-500">Arch. by Sun Haojun (PRI)</span>
            </div>

            {/* Empty State Overlay */}
            {!hasValidData && (
                <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-slate-50/80 dark:bg-slate-900/80 backdrop-blur-sm">
                    <div className="bg-white dark:bg-slate-800 p-8 rounded-3xl shadow-2xl text-center border border-slate-100 dark:border-slate-700 max-w-sm">
                        <div className="w-16 h-16 bg-slate-100 dark:bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-4">
                            <AlertTriangle className="text-amber-500" size={32} />
                        </div>
                        <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-2">Insufficient Data</h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400 mb-6">
                            Please select products containing valid numeric properties for {tProp(activeChart)} analysis.
                        </p>
                    </div>
                </div>
            )}
         </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { X, Save, User, Mail, Lock, Camera, CheckCircle2, Loader2, ShieldCheck, Trash2, RotateCcw } from 'lucide-react';
import { User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';

interface ProfileModalProps {
  isOpen: boolean;
  onClose: () => void;
  user: UserType | null;
  onSave: (updatedUser: any) => void;
}

export const ProfileModal: React.FC<ProfileModalProps> = ({ isOpen, onClose, user, onSave }) => {
  const { t } = useLanguage();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [avatar, setAvatar] = useState('');
  const [isSaving, setIsSaving] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  useEffect(() => {
    if (user && isOpen) {
      setName(user.name);
      setEmail(user.email);
      setAvatar(user.avatar || '');
      setPassword(''); 
      setShowSuccess(false);
    }
  }, [user, isOpen]);

  if (!isOpen || !user) return null;

  const handleLocalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert("File too large. Please use an image under 2MB.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatar(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const resetToDefault = () => {
    setAvatar(`https://api.dicebear.com/7.x/avataaars/svg?seed=${name}`);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);

    setTimeout(() => {
      const updatedData: any = {
        name,
        email,
        avatar
      };
      if (password) updatedData.password = password;

      onSave(updatedData);
      setIsSaving(false);
      setShowSuccess(true);

      setTimeout(() => {
        onClose();
      }, 1500);
    }, 1000);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-300">
      <div className="w-full max-w-lg bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
        <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50/50 dark:bg-slate-950/50">
          <div className="flex items-center gap-3">
             <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 rounded-xl">
                <User size={20} />
             </div>
             <h3 className="text-lg font-bold text-slate-900 dark:text-white">{t('editProfile')}</h3>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
