import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';

type Theme = 'light' | 'dark';
export type ColorTheme = 'indigo' | 'emerald' | 'rose' | 'blue' | 'amber' | 'violet';

interface ThemeContextType {
  theme: Theme;
  colorTheme: ColorTheme;
  toggleTheme: () => void;
  setColorTheme: (color: ColorTheme) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

// Color Palettes Definition (Tailwind Colors 50-950)
const PALETTES: Record<ColorTheme, Record<string, string>> = {
  indigo: { // Default
    50: '#eef2ff', 100: '#e0e7ff', 200: '#c7d2fe', 300: '#a5b4fc', 400: '#818cf8', 
    500: '#6366f1', 600: '#4f46e5', 700: '#4338ca', 800: '#3730a3', 900: '#312e81', 950: '#1e1b4b',
    rgb: '99, 102, 241' // for 500
  },
  emerald: { // Green/Safe
    50: '#ecfdf5', 100: '#d1fae5', 200: '#a7f3d0', 300: '#6ee7b7', 400: '#34d399', 
    500: '#10b981', 600: '#059669', 700: '#047857', 800: '#065f46', 900: '#064e3b', 950: '#022c22',
    rgb: '16, 185, 129'
  },
  rose: { // Red/Warm
    50: '#fff1f2', 100: '#ffe4e6', 200: '#fecdd3', 300: '#fda4af', 400: '#fb7185', 
    500: '#f43f5e', 600: '#e11d48', 700: '#be123c', 800: '#9f1239', 900: '#881337', 950: '#4c0519',
    rgb: '244, 63, 94'
  },
  blue: { // Corporate/Tech
    50: '#eff6ff', 100: '#dbeafe', 200: '#bfdbfe', 300: '#93c5fd', 400: '#60a5fa', 
    500: '#3b82f6', 600: '#2563eb', 700: '#1d4ed8', 800: '#1e40af', 900: '#1e3a8a', 950: '#172554',
    rgb: '59, 130, 246'
  },
  amber: { // Energy/Warning
    50: '#fffbeb', 100: '#fef3c7', 200: '#fde68a', 300: '#fcd34d', 400: '#fbbf24', 
    500: '#f59e0b', 600: '#d97706', 700: '#b45309', 800: '#92400e', 900: '#78350f', 950: '#451a03',
    rgb: '245, 158, 11'
  },
  violet: { // Creative/Future
    50: '#f5f3ff', 100: '#ede9fe', 200: '#ddd6fe', 300: '#c4b5fd', 400: '#a78bfa', 
    500: '#8b5cf6', 600: '#7c3aed', 700: '#6d28d9', 800: '#5b21b6', 900: '#4c1d95', 950: '#2e1065',
    rgb: '139, 92, 246'
  }
};

export const ThemeProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  // Light/Dark Theme
  const [theme, setTheme] = useState<Theme>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('resindb-theme');
        if (!saved && window.matchMedia('(prefers-color-scheme: dark)').matches) return 'dark';
        return (saved as Theme) || 'light';
    }
    return 'light';
  });

  // Color Theme
  const [colorTheme, setColorTheme] = useState<ColorTheme>(() => {
      if (typeof window !== 'undefined') {
          return (localStorage.getItem('resindb-color-theme') as ColorTheme) || 'indigo';
      }
      return 'indigo';
  });

  // Apply Light/Dark
  useEffect(() => {
    const root = document.documentElement;
    localStorage.setItem('resindb-theme', theme);
    if (theme === 'dark') {
      root.classList.add('dark');
      root.style.colorScheme = 'dark';
    } else {
      root.classList.remove('dark');
      root.style.colorScheme = 'light';
    }
  }, [theme]);

  // Apply Color Palette
  useEffect(() => {
      const root = document.documentElement;
      localStorage.setItem('resindb-color-theme', colorTheme);
      const palette = PALETTES[colorTheme];

      // Update CSS Variables dynamically
      Object.entries(palette).forEach(([key, value]) => {
          const val = value as string;
          if (key === 'rgb') {
              root.style.setProperty('--color-primary-500-rgb', val);
          } else {
              root.style.setProperty(`--color-primary-${key}`, val);
          }
      });
  }, [colorTheme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  return (
    <ThemeContext.Provider value={{ theme, colorTheme, toggleTheme, setColorTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

import React, { useState, useEffect } from 'react';
import { X, Save, Plus, Trash2, Beaker, Factory, Loader2, Settings2, ChevronDown, ChevronUp, Link as LinkIcon, BookOpen, Hash, Thermometer, FileText } from 'lucide-react';
import { Product, PropertyValue } from '../types';
import { useLanguage } from '../contexts/LanguageContext';

interface EditProductModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (product: Product) => Promise<boolean> | void;
  product: Product | null;
}

interface PropertyRow {
  id: string;
  key: string;
  value: string;
  unit: string;
  // Metadata fields
  standard: string;
  instrument: string;
  temperature: string;
  referenceId: string;
  sourceUrl: string;
  isExpanded: boolean;
}

export const EditProductModal: React.FC<EditProductModalProps> = ({ isOpen, onClose, onSave, product }) => {
  const { t, tProp } = useLanguage();
  const [formData, setFormData] = useState<Partial<Product>>({});
  const [propertyRows, setPropertyRows] = useState<PropertyRow[]>([]);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    if (product) {
      setFormData({
        gradeName: product.gradeName,
        manufacturer: product.manufacturer,
        categoryIds: product.categoryIds
      });

      const rows = Object.entries(product.properties).map(([key, v], index) => {
        const val = v as PropertyValue;
        return {
            id: `prop-${index}-${Date.now()}`,
            key,
            value: String(val.value),
            unit: val.unit || '',
            standard: val.standard || '',
            instrument: val.instrument || '',
            temperature: val.temperature || '',
            referenceId: val.referenceId || '',
            sourceUrl: val.sourceUrl || '',
            isExpanded: false
        };
      });
      setPropertyRows(rows);
    }
  }, [product, isOpen]);

  const handleSave = async () => {
    if (!product || isSaving) return;
    setIsSaving(true);

    const newProperties: Record<string, PropertyValue> = {};
    propertyRows.forEach(row => {
      if (row.key.trim()) {
        const numVal = Number(row.value);
        newProperties[row.key] = {
          value: !isNaN(numVal) && row.value.trim() !== '' ? numVal : row.value,
          unit: row.unit.trim() || undefined,
          standard: row.standard.trim() || undefined,
          instrument: row.instrument.trim() || undefined,
          temperature: row.temperature.trim() || undefined,
          referenceId: row.referenceId.trim() || undefined,
          sourceUrl: row.sourceUrl.trim() || undefined
        };
      }
    });

    const updatedProduct = {
      ...product,
      ...formData as Product,
      properties: newProperties,
      updatedAt: new Date().toISOString().split('T')[0]
    };

    try {
        await onSave(updatedProduct);
        onClose();
    } catch (e) {
        // Error handling done in parent
    } finally {
        setIsSaving(false);
    }
  };

  const addRow = () => {
    setPropertyRows([...propertyRows, { 
        id: `new-${Date.now()}`, 
        key: '', value: '', unit: '', 
        standard: '', instrument: '', temperature: '', referenceId: '', sourceUrl: '',
        isExpanded: true 
    }]);
  };

  const removeRow = (id: string) => {
    setPropertyRows(propertyRows.filter(r => r.id !== id));
  };

  const updateRow = (id: string, field: keyof PropertyRow, val: any) => {
    setPropertyRows(propertyRows.map(r => r.id === id ? { ...r, [field]: val } : r));
  };

  const toggleExpand = (id: string) => {
    setPropertyRows(propertyRows.map(r => r.id === id ? { ...r, isExpanded: !r.isExpanded } : r));
  };

  if (!isOpen || !product) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-300">
      <div className="w-full max-w-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50 dark:bg-slate-950/50">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 rounded-xl">
               <Beaker size={20} />
            </div>
            <h3 className="text-lg font-bold text-slate-900 dark:text-white">{t('editProduct')}</h3>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 custom-scrollbar space-y-6">
           <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                 <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">{tProp('牌号')}</label>
                 <input 
                    className="w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-900 dark:text-slate-100 outline-none focus:border-emerald-500 transition-all"
                    value={formData.gradeName || ''}
                    onChange={e => setFormData({...formData, gradeName: e.target.value})}
                 />
              </div>
              <div className="space-y-1.5">
                 <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">{tProp('生产厂家')}</label>
                 <div className="relative">
                    <Factory size={16} className="absolute left-3.5 top-3 text-slate-400" />
