                                        className="w-full px-2 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs outline-none focus:border-emerald-500 font-mono text-blue-600 dark:text-blue-400"
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[9px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
                                        <FileText size={10} /> {t('standard')}
                                    </label>
                                    <input 
                                        value={row.standard}
                                        onChange={e => updateRow(row.id, 'standard', e.target.value)}
                                        placeholder="e.g. ISO 1133"
                                        className="w-full px-2 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs outline-none focus:border-emerald-500"
                                    />
