                                <div className="space-y-1">
                                    <label className="text-[9px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
                                        <Thermometer size={10} /> {t('testConditions')}
                                    </label>
                                    <input 
                                        value={row.temperature}
                                        onChange={e => updateRow(row.id, 'temperature', e.target.value)}
                                        placeholder="e.g. 230°C/2.16kg"
                                        className="w-full px-2 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs outline-none focus:border-emerald-500"
                                    />
                                </div>
                            </div>
                        )}
                    </div>
                 ))}
              </div>
