         <div className="flex flex-col gap-4 mb-2">
            <button onClick={() => setIsAdminOpen(true)} className="w-12 h-12 flex items-center justify-center text-slate-500 hover:text-amber-400 hover:bg-slate-800 rounded-2xl transition-all"><ShieldCheck size={22} /></button>
         </div>
      </nav>

      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <div className="shrink-0 z-[60] relative">
            <TopBar 
