                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-tighter">生成报告</span>
                        </button>
                        <button onClick={() => handleDelete(Array.from(selectedIds))} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-rose-100 rounded-2xl text-white dark:text-rose-700 hover:bg-rose-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Trash2 size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-tighter">{t('delete')}</span>
                        </button>
                    </div>
                </div>
            </div>
        )}
      </div>

      <ImportModal isOpen={isImportOpen} onClose={() => setIsImportOpen(false)} onImport={handleImportData} />
      <ProfileModal isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} user={currentUser} onSave={handleUpdateUserProfile} />
      <AdminModal isOpen={isAdminOpen} onClose={() => setIsAdminOpen(false)} />
      {activeView !== 'ai' && <AIAssistant contextData={aiContextData} />}
      <ProductDetailDrawer product={viewingProduct} onClose={() => setViewingProduct(null)} onCategoryClick={selectSingleCategory} />
      {isComparisonOpen && <ComparisonView products={productsToCompare} onClose={() => setIsComparisonOpen(false)} onRemoveProduct={(id) => { const next = new Set(selectedIds); next.delete(id); setSelectedIds(next); if(next.size === 0) setIsComparisonOpen(false); }} />}
    </div>
  );
};

