import React, { useState, useMemo, useRef, useEffect } from 'react';
import { 
  Settings, Activity, X, FileJson, Image as ImageIcon, 
  Hexagon, ScatterChart, Waves, Triangle, Info, Loader2,
  Filter, Plus, Trash2, ChevronDown, Check, AlertTriangle,
  Thermometer, Target
} from 'lucide-react';
import * as echarts from 'echarts';
import { Product, PropertyValue } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { ScientificChart, ChartType } from './ScientificChart';

interface DataVisualizerProps {
  data: Product[];
  selectedProducts?: Product[];
  initialChartType?: string;
}

export const DataVisualizer: React.FC<DataVisualizerProps> = ({ data, selectedProducts, initialChartType }) => {
  const { t, tProp } = useLanguage();
  const [chartInstance, setChartInstance] = useState<echarts.ECharts | null>(null);
  const [activeChart, setActiveChart] = useState<ChartType>('radar');
  const [showConfig, setShowConfig] = useState(true);
  const [isExporting, setIsExporting] = useState(false);

  // Rheology specific configuration
  const [selectedRheologyTemps, setSelectedRheologyTemps] = useState<number[]>([190, 210, 230]);

  // Sync with initialChartType from props (navigation from AI)
  useEffect(() => {
    if (initialChartType && ['radar', 'ashby', 'mfr_density', 'gpc', 'rheology', 'ternary'].includes(initialChartType)) {
      setActiveChart(initialChartType as ChartType);
    }
  }, [initialChartType]);

  // Filter State
  const [filters, setFilters] = useState<Record<string, { min: string; max: string }>>({});
  const [isFilterDropdownOpen, setIsFilterDropdownOpen] = useState(false);
  const filterDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (filterDropdownRef.current && !filterDropdownRef.current.contains(event.target as Node)) {
              setIsFilterDropdownOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Determine base data set
  const baseData = useMemo(() => {
    return (selectedProducts && selectedProducts.length > 0) ? selectedProducts : data;
  }, [data, selectedProducts]);

  // Extract available numeric properties for filtering - Memoized to prevent heavy loop on every render
  const numericProperties = useMemo(() => {
      if (!baseData) return [];
      const props = new Set<string>();
      baseData.forEach(p => {
          Object.entries(p.properties).forEach(([key, v]) => {
              const val = v as PropertyValue; // Cast value
              const num = parseFloat(String(val.value));
              if (!isNaN(num)) props.add(key);
          });
      });
      return Array.from(props).sort();
  }, [baseData]);

  // Apply filters to baseData
  const filteredData = useMemo(() => {
      if (!baseData) return [];
      if (Object.keys(filters).length === 0) return baseData;

      return baseData.filter(p => {
          return (Object.entries(filters) as [string, { min: string, max: string }][]).every(([key, { min, max }]) => {
              const val = p.properties[key]?.value;
              const numVal = parseFloat(String(val));

              if (isNaN(numVal)) return false; 

              const minVal = min === '' ? -Infinity : parseFloat(min);
              const maxVal = max === '' ? Infinity : parseFloat(max);

              return numVal >= minVal && numVal <= maxVal;
          });
      });
  }, [baseData, filters]);

  // Helper: Safe Float Parser (Layer 1: Anti-Crash)
  const safeParse = (val: any, fallback = 0): number => {
      if (val === undefined || val === null || val === '') return fallback;
      const num = parseFloat(String(val));
      return isNaN(num) ? fallback : num;
  };

  const handleAddFilter = (key: string) => {
      if (!filters[key]) {
          setFilters(prev => ({ ...prev, [key]: { min: '', max: '' } }));
      }
      setIsFilterDropdownOpen(false);
  };

  const updateFilter = (key: string, field: 'min' | 'max', val: string) => {
      // Allow only numbers and decimals
      if (val && !/^-?\d*\.?\d*$/.test(val)) return;
      setFilters(prev => ({
          ...prev,
          [key]: { ...prev[key], [field]: val }
      }));
  };

  const removeFilter = (key: string) => {
      setFilters(prev => {
          const next = { ...prev };
          delete next[key];
          return next;
      });
  };

  // --- Data Preparation Logic (Defensive) using filteredData ---

  // 1. Radar Data: Compare top 5 (or selected) products
  const radarData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const source = filteredData.slice(0, 5); 
        return source.map(p => ({
          name: p.gradeName,
          value: [
            safeParse(p.properties['熔体质量流动速率']?.value),
            safeParse(p.properties['密度']?.value),
            safeParse(p.properties['弯曲模量']?.value),
            safeParse(p.properties['拉伸屈服应力']?.value),
            safeParse(p.properties['悬臂梁缺口冲击强度']?.value)
          ]
        }));
    } catch (e) {
        console.error("Radar Prep Error:", e);
        return [];
    }
  }, [filteredData]);

  // 2. Ashby Data: MFR vs Impact
  const ashbyData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const groups: Record<string, any[]> = {};
        filteredData.forEach(p => {
          const man = p.manufacturer || 'Unknown';
          if (!groups[man]) groups[man] = [];

          const mfr = safeParse(p.properties['熔体质量流动速率']?.value, -1);
          const impact = safeParse(p.properties['悬臂梁缺口冲击强度']?.value, -1);

          if (mfr > 0 && impact > 0) {
            groups[man].push([mfr, impact, p.gradeName]);
          }
        });

        return Object.entries(groups).map(([name, points]) => ({
          name,
          data: points
        }));
    } catch(e) {
        console.error("Ashby Prep Error:", e);
        return [];
    }
  }, [filteredData]);

  // 3. MFR vs Density Data
  const mfrDensityData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const groups: Record<string, any[]> = {};
        filteredData.forEach(p => {
          const man = p.manufacturer || 'Unknown';
          if (!groups[man]) groups[man] = [];

          const mfr = safeParse(p.properties['熔体质量流动速率']?.value, -1);
          const density = safeParse(p.properties['密度']?.value, -1);

          if (mfr > 0 && density > 0) {
            groups[man].push([mfr, density, p.gradeName]);
          }
        });

        return Object.entries(groups).map(([name, points]) => ({
          name,
          data: points
        }));
    } catch(e) {
        console.error("MFR-Density Prep Error:", e);
        return [];
    }
  }, [filteredData]);

  // 5. Ternary Data: Mock Formulation (Simulated based on properties)
  const ternaryData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const source = filteredData.length > 0 ? filteredData : [];
        return source.slice(0, 100).map((p, i) => {
            // Simulation logic to create 3 clusters based on density/MFR
            const mfr = safeParse(p.properties['熔体质量流动速率']?.value, 1);
            let a, b, c;

            if (mfr < 1) {
                a = 0.6 + Math.random() * 0.3;
                b = Math.random() * (0.9 - a);
                c = 1 - a - b;
            } else if (mfr > 10) {
                b = 0.6 + Math.random() * 0.3;
                a = Math.random() * (0.9 - b);
                c = 1 - a - b;
            } else {
                c = 0.5 + Math.random() * 0.4;
                a = Math.random() * (0.9 - c);
                b = 1 - a - c;
            }

            const sum = a + b + c;
            a = a / sum;
            b = b / sum;
            c = c / sum;

            return {
                a, b, c,
                name: p.gradeName,
                value: safeParse(p.properties['拉伸强度']?.value, 50) + (Math.random() * 10 - 5)
