interface PropertyRow {
  id: string;
  key: string;
  value: string;
  unit: string;
  // Metadata fields
  standard: string;
  instrument: string;
  temperature: string;
  referenceId: string;
  sourceUrl: string;
  isExpanded: boolean;
}

export const EditProductModal: React.FC<EditProductModalProps> = ({ isOpen, onClose, onSave, product }) => {
  const { t, tProp } = useLanguage();
  const [formData, setFormData] = useState<Partial<Product>>({});
  const [propertyRows, setPropertyRows] = useState<PropertyRow[]>([]);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    if (product) {
      setFormData({
        gradeName: product.gradeName,
        manufacturer: product.manufacturer,
        categoryIds: product.categoryIds
      });

      const rows = Object.entries(product.properties).map(([key, v], index) => {
        const val = v as PropertyValue; // Explicit Cast
        return {
            id: `prop-${index}-${Date.now()}`,
            key,
            value: String(val.value),
            unit: val.unit || '',
            standard: val.standard || '',
            instrument: val.instrument || '',
            temperature: val.temperature || '',
            referenceId: val.referenceId || '',
            sourceUrl: val.sourceUrl || '',
            isExpanded: false
        };
      });
      setPropertyRows(rows);
    }
  }, [product, isOpen]);

  const handleSave = async () => {
    if (!product || isSaving) return;
    setIsSaving(true);

    const newProperties: Record<string, PropertyValue> = {};
    propertyRows.forEach(row => {
      if (row.key.trim()) {
        const numVal = Number(row.value);
        newProperties[row.key] = {
          value: !isNaN(numVal) && row.value.trim() !== '' ? numVal : row.value,
          unit: row.unit.trim() || undefined,
          standard: row.standard.trim() || undefined,
          instrument: row.instrument.trim() || undefined,
          temperature: row.temperature.trim() || undefined,
          referenceId: row.referenceId.trim() || undefined,
          sourceUrl: row.sourceUrl.trim() || undefined
        };
      }
    });

    const updatedProduct = {
      ...product,
      ...formData as Product,
      properties: newProperties,
      updatedAt: new Date().toISOString().split('T')[0]
    };

    try {
        await onSave(updatedProduct);
        onClose();
    } catch (e) {
        // Error handling done in parent
    } finally {
        setIsSaving(false);
    }
  };

  const addRow = () => {
    setPropertyRows([...propertyRows, { 
        id: `new-${Date.now()}`, 
        key: '', value: '', unit: '', 
        standard: '', instrument: '', temperature: '', referenceId: '', sourceUrl: '',
        isExpanded: true 
    }]);
  };

  const removeRow = (id: string) => {
    setPropertyRows(propertyRows.filter(r => r.id !== id));
  };

  const updateRow = (id: string, field: keyof PropertyRow, val: any) => {
    setPropertyRows(propertyRows.map(r => r.id === id ? { ...r, [field]: val } : r));
  };

  const toggleExpand = (id: string) => {
    setPropertyRows(propertyRows.map(r => r.id === id ? { ...r, isExpanded: !r.isExpanded } : r));
  };

  if (!isOpen || !product) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-300">
      <div className="w-full max-w-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50 dark:bg-slate-950/50">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 rounded-xl">
               <Beaker size={20} />
            </div>
            <h3 className="text-lg font-bold text-slate-900 dark:text-white">{t('editProduct')}</h3>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 custom-scrollbar space-y-6">
           <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                 <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">{tProp('牌号')}</label>
                 <input 
                    className="w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-900 dark:text-slate-100 outline-none focus:border-emerald-500 transition-all"
                    value={formData.gradeName || ''}
                    onChange={e => setFormData({...formData, gradeName: e.target.value})}
                 />
              </div>
              <div className="space-y-1.5">
                 <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">{tProp('生产厂家')}</label>
                 <div className="relative">
                    <Factory size={16} className="absolute left-3.5 top-3 text-slate-400" />
                    <input 
                        className="w-full pl-10 pr-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-900 dark:text-slate-100 outline-none focus:border-emerald-500 transition-all"
                        value={formData.manufacturer || ''}
                        onChange={e => setFormData({...formData, manufacturer: e.target.value})}
                    />
                 </div>
              </div>
           </div>

           <div className="space-y-3">
              <div className="flex items-center justify-between border-b border-slate-100 dark:border-slate-800 pb-2">
                 <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest">{t('properties')}</h4>
                 <button onClick={addRow} className="flex items-center gap-1 text-[10px] font-bold text-emerald-600 hover:text-emerald-500 bg-emerald-50 dark:bg-emerald-900/20 px-2 py-1 rounded-lg transition-colors">
                    <Plus size={12} /> {t('addProperty')}
                 </button>
              </div>

              <div className="space-y-2">
                 {propertyRows.map((row) => (
                    <div key={row.id} className="group bg-white dark:bg-slate-900 rounded-xl border border-transparent hover:border-slate-100 dark:hover:border-slate-800 transition-colors p-1">
                        <div className="flex items-center gap-2">
                           <button 
                                onClick={() => toggleExpand(row.id)}
                                className={`p-2 rounded-lg transition-colors ${row.isExpanded ? 'text-primary-500 bg-primary-50 dark:bg-primary-900/20' : 'text-slate-300 hover:text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'}`}
                                title="Edit Metadata & Source"
                           >
                                <Settings2 size={16} />
                           </button>
                           <input 
                              placeholder={t('propertyName')}
                              value={row.key}
                              onChange={e => updateRow(row.id, 'key', e.target.value)}
                              className="flex-1 px-3 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-bold text-slate-700 dark:text-slate-300 outline-none focus:border-emerald-500 transition-all"
                           />
                           <input 
                              placeholder={t('propertyValue')}
                              value={row.value}
                              onChange={e => updateRow(row.id, 'value', e.target.value)}
                              className="flex-1 px-3 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-mono text-emerald-600 dark:text-emerald-400 outline-none focus:border-emerald-500 transition-all"
                           />
                           <input 
                              placeholder={t('propertyUnit')}
                              value={row.unit}
                              onChange={e => updateRow(row.id, 'unit', e.target.value)}
                              className="w-20 px-3 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xs text-slate-500 outline-none focus:border-emerald-500 transition-all"
                           />
                           <button onClick={() => removeRow(row.id)} className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg transition-colors opacity-0 group-hover:opacity-100">
                              <Trash2 size={16} />
                           </button>
                        </div>

                        {/* Expandable Metadata Section */}
                        {row.isExpanded && (
                            <div className="mt-2 ml-10 mr-10 p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800/50 grid grid-cols-2 gap-3 animate-in slide-in-from-top-1">
                                <div className="space-y-1">
                                    <label className="text-[9px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
                                        <Hash size={10} /> {t('referenceId')}
                                    </label>
                                    <input 
                                        value={row.referenceId}
                                        onChange={e => updateRow(row.id, 'referenceId', e.target.value)}
                                        placeholder="e.g. Lab-2024-001"
                                        className="w-full px-2 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs outline-none focus:border-emerald-500"
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[9px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
                                        <Beaker size={10} /> {t('sourceEquipment')}
                                    </label>
                                    <input 
                                        value={row.instrument}
                                        onChange={e => updateRow(row.id, 'instrument', e.target.value)}
                                        placeholder="e.g. Mettler Toledo"
                                        className="w-full px-2 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs outline-none focus:border-emerald-500"
                                    />
                                </div>
                                <div className="space-y-1 col-span-2">
                                    <label className="text-[9px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
                                        <LinkIcon size={10} /> {t('sourceUrl')}
                                    </label>
                                    <input 
                                        value={row.sourceUrl}
                                        onChange={e => updateRow(row.id, 'sourceUrl', e.target.value)}
                                        placeholder="https://..."
                                        className="w-full px-2 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs outline-none focus:border-emerald-500 font-mono text-blue-600 dark:text-blue-400"
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[9px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
                                        <FileText size={10} /> {t('standard')}
                                    </label>
                                    <input 
                                        value={row.standard}
                                        onChange={e => updateRow(row.id, 'standard', e.target.value)}
                                        placeholder="e.g. ISO 1133"
                                        className="w-full px-2 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs outline-none focus:border-emerald-500"
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[9px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
                                        <Thermometer size={10} /> {t('testConditions')}
                                    </label>
                                    <input 
                                        value={row.temperature}
                                        onChange={e => updateRow(row.id, 'temperature', e.target.value)}
                                        placeholder="e.g. 230°C/2.16kg"
                                        className="w-full px-2 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-xs outline-none focus:border-emerald-500"
                                    />
                                </div>
                            </div>
                        )}
                    </div>
                 ))}
              </div>
           </div>
        </div>

        {/* Footer */}
        <div className="px-6 py-4 border-t border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-950/50 flex justify-end gap-3">
           <button onClick={onClose} className="px-6 py-2.5 text-xs font-black uppercase tracking-widest text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 transition-colors">{t('cancel')}</button>
           <button 
             onClick={handleSave} 
             disabled={isSaving}
             className="px-8 py-2.5 bg-emerald-600 hover:bg-emerald-500 text-white text-xs font-black uppercase tracking-widest rounded-xl shadow-xl shadow-emerald-500/20 transition-all active:scale-95 flex items-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed"
           >
              {isSaving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
              {isSaving ? 'SAVING...' : t('save')}
           </button>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo, useEffect, useRef } from 'react';
import { X, ChevronRight, Layers, Factory, Microscope, LayoutGrid, Globe, Info, BookOpen, ExternalLink, Calendar, FileText, ShieldCheck, Link2, Activity, Flame, Zap, TestTube, Box, FlaskConical, Beaker, Hash, Radar } from 'lucide-react';
import { Product, Category, Manufacturer, Reference, PropertyValue } from '../types';
import { CATEGORY_TREE, MANUFACTURERS, REFERENCES, PROPERTY_GROUPS } from '../constants';
import { useLanguage } from '../contexts/LanguageContext';
import * as echarts from 'echarts';

interface ProductDetailDrawerProps {
  product: Product | null;
  onClose: () => void;
  onCategoryClick: (id: string) => void;
}

export const ProductDetailDrawer: React.FC<ProductDetailDrawerProps> = ({ product, onClose, onCategoryClick }) => {
  const { t, tProp, language } = useLanguage();
  const chartRef = useRef<HTMLDivElement>(null);

  const manufacturer = useMemo(() => 
    MANUFACTURERS.find(m => m.id === product?.manufacturerId), 
  [product]);

  const relevantRefs = useMemo(() => {
    if (!product) return [];
    const refIds = new Set((Object.values(product.properties) as PropertyValue[]).map(p => p.referenceId).filter(Boolean));
    return REFERENCES.filter(r => refIds.has(r.id as string));
  }, [product]);

  const allPaths = useMemo(() => {
    if (!product) return [];
    const paths: {segments: string[], leafId: string}[] = [];

    const findPaths = (nodes: Category[], targetId: string, currentPath: string[]) => {
      for (const node of nodes) {
        const nodeName = language === 'en' && node.nameEn ? node.nameEn : node.name;
        const newPath = [...currentPath, nodeName];
        if (node.id === targetId) {
            paths.push({ segments: newPath, leafId: node.id });
        }
        if (node.children) findPaths(node.children, targetId, newPath);
      }
    };

    product.categoryIds.forEach(id => findPaths(CATEGORY_TREE, id, []));
    return paths;
  }, [product, language]);

  const groupedProperties = useMemo<Record<string, [string, PropertyValue][]>>(() => {
      if (!product) return {};
      const groups: Record<string, [string, PropertyValue][]> = {
          'General': [],
          'Mechanical': [],
          'Thermal': [],
          'Optical/Electrical': [],
          'Chemical': [],
          'Other': []
      };

      Object.entries(product.properties).forEach(([key, val]) => {
          let found = false;
          for (const groupName in PROPERTY_GROUPS) {
              if (PROPERTY_GROUPS[groupName].some(k => key.includes(k) || k === key)) {
                  groups[groupName].push([key, val as PropertyValue]);
                  found = true;
                  break;
              }
          }
          if (!found) groups['Other'].push([key, val as PropertyValue]);
      });

      return groups;
  }, [product]);

  // Mini Radar Chart Effect
  useEffect(() => {
      if (!product || !chartRef.current) return;

      const myChart = echarts.init(chartRef.current);
      const props = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度'];
      const values = props.map(p => {
          const v = product.properties?.[p]?.value;
          return typeof v === 'number' ? v : parseFloat(String(v)) || 0;
      });

      // Normalize values roughly for visualization (mock scale)
      // Ideally this should normalize against category min/max
      const normalizedValues = [
          (values[0] || 0) * 100, // Density ~0.95 -> 95
          (values[1] || 0) * 10,  // MFR ~1-10 -> 10-100
          (values[2] || 0) * 2,   // Tensile ~25 -> 50
          (values[3] || 0) / 20,  // Flex ~1000 -> 50
          (values[4] || 0) * 3    // Impact ~10 -> 30
      ];

      const option = {
          radar: {
              indicator: props.map(p => ({ name: tProp(p).slice(0, 6), max: 100 })),
              radius: '65%',
              center: ['50%', '50%'],
              splitNumber: 3,
              axisName: { color: '#94a3b8', fontSize: 9, fontWeight: 'bold' },
              splitLine: { lineStyle: { color: 'rgba(148, 163, 184, 0.2)' } },
              splitArea: { show: false },
              axisLine: { lineStyle: { color: 'rgba(148, 163, 184, 0.2)' } }
          },
          series: [{
              type: 'radar',
              data: [{ 
                  value: normalizedValues,
                  areaStyle: { color: 'rgba(16, 185, 129, 0.2)' },
                  lineStyle: { color: '#10b981', width: 2 },
                  symbol: 'none'
              }]
          }]
      };

      myChart.setOption(option);

      const resize = () => myChart.resize();
      window.addEventListener('resize', resize);
      return () => {
          window.removeEventListener('resize', resize);
          myChart.dispose();
      };
  }, [product, tProp]);

  if (!product) return null;

  const getGroupIcon = (name: string) => {
      switch(name) {
          case 'Mechanical': return <Activity size={16} className="text-blue-500" />;
          case 'Thermal': return <Flame size={16} className="text-orange-500" />;
          case 'Optical/Electrical': return <Zap size={16} className="text-yellow-500" />;
          case 'Chemical': return <TestTube size={16} className="text-purple-500" />;
          case 'General': return <Box size={16} className="text-emerald-500" />;
          default: return <LayoutGrid size={16} className="text-slate-400" />;
      }
  };

  const getGroupName = (name: string) => {
      const key = `group_${name.replace('/', '').replace(' ', '')}`;
      return t(key as any) || name;
  };

  return (
    <div className={`fixed inset-y-0 right-0 w-full sm:w-[640px] bg-white dark:bg-slate-900 shadow-2xl z-[60] border-l border-slate-200 dark:border-slate-800 transition-transform duration-300 transform ${product ? 'translate-x-0' : 'translate-x-full'} flex flex-col`}>
      {/* Header */}
      <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50 dark:bg-slate-950/50 backdrop-blur-sm sticky top-0 z-10">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-emerald-500/20">
            <Microscope size={24} />
          </div>
          <div>
            <h3 className="text-xl font-black text-slate-900 dark:text-white leading-tight tracking-tight">{product.gradeName}</h3>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-[10px] font-bold bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-400 px-2 py-0.5 rounded-full uppercase tracking-wider">{t('tdsReport')}</span>
                <span className="text-[10px] text-slate-400 font-medium">Updated: {product.updatedAt}</span>
            </div>
          </div>
        </div>
        <button onClick={onClose} className="p-2 text-slate-400 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl transition-all">
          <X size={24} />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 custom-scrollbar space-y-8 bg-slate-50/30 dark:bg-slate-950/30">

        {/* Manufacturer & Radar Card Row */}
        <div className="flex flex-col sm:flex-row gap-4">
            {manufacturer && (
                <div className="flex-1 bg-white dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-2xl p-5 relative overflow-hidden group shadow-sm">
                    <div className="absolute top-0 right-0 p-6 opacity-[0.03] pointer-events-none group-hover:scale-110 transition-transform duration-700"><Factory size={120} /></div>
                    <div className="relative z-10 h-full flex flex-col justify-between">
                        <div>
                            <div className="flex items-center gap-3 mb-3">
                                <div className="p-2.5 bg-blue-50 dark:bg-blue-900/20 rounded-xl text-blue-600 dark:text-blue-400">
                                    <Factory size={20} />
                                </div>
                                <div>
                                    <h4 className="text-base font-bold text-slate-900 dark:text-white">{manufacturer.name}</h4>
                                    <div className="flex items-center gap-1.5 mt-0.5">
                                        <ShieldCheck size={12} className="text-emerald-500" />
                                        <span className="text-[10px] font-medium text-emerald-600 dark:text-emerald-400 uppercase tracking-wide">{t('verifiedManufacturer')}</span>
                                    </div>
                                </div>
                            </div>
                            <p className="text-xs text-slate-600 dark:text-slate-300 leading-relaxed mb-4 line-clamp-2">
                                {manufacturer.description}
                            </p>
                        </div>
                        {manufacturer.website && (
                            <a 
                                href={manufacturer.website.startsWith('http') ? manufacturer.website : `https://${manufacturer.website}`} 
                                target="_blank" 
                                rel="noreferrer" 
                                className="flex items-center gap-2 px-4 py-2 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-xl text-xs font-bold hover:opacity-90 transition-opacity shadow-lg shadow-slate-500/10 w-fit"
                            >
                                <Globe size={14} /> {t('officialWebsite')}
                            </a>
                        )}
                    </div>
                </div>
            )}

            {/* Visual Radar */}
            <div className="w-full sm:w-48 h-48 bg-white dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-2xl p-2 relative flex flex-col items-center justify-center shrink-0">
                <div className="absolute top-3 left-3 flex items-center gap-1.5 text-[10px] font-black text-slate-400 uppercase tracking-widest z-10">
                    <Radar size={12} className="text-emerald-500" /> Fingerprint
                </div>
                <div ref={chartRef} className="w-full h-full" />
            </div>
        </div>

        {/* Multi-path Classification */}
        <section className="space-y-3">
          <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
            <Link2 size={12} className="text-blue-500" />
            {t('taxonomyPaths')}
          </div>
          <div className="space-y-2">
            {allPaths.map((path, idx) => (
              <button 
                key={idx} 
                onClick={() => onCategoryClick(path.leafId)} 
                className="w-full text-left group flex items-center p-2 rounded-xl bg-white dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 hover:border-emerald-400 dark:hover:border-emerald-600 transition-all shadow-sm hover:shadow-md"
              >
                <div className="flex flex-wrap items-center text-xs">
                  {path.segments.map((segment, sIdx) => (
                    <React.Fragment key={sIdx}>
                      <span className={`font-medium transition-colors ${sIdx === path.segments.length - 1 ? 'font-bold text-slate-800 dark:text-white' : 'text-slate-500 dark:text-slate-400'}`}>{segment}</span>
                      {sIdx < path.segments.length - 1 && <ChevronRight size={12} className="mx-1.5 text-slate-300" />}
                    </React.Fragment>
                  ))}
                </div>
              </button>
            ))}
          </div>
        </section>

        {/* Property Groups */}
        <div className="space-y-8">
            {Object.entries(groupedProperties).map(([groupName, items]) => {
                if (items.length === 0) return null;
                return (
                    <section key={groupName} className="animate-in fade-in slide-in-from-bottom-2 duration-500">
                        <div className="flex items-center gap-2 mb-4 pb-2 border-b border-slate-200 dark:border-slate-700">
                            {getGroupIcon(groupName)}
                            <h4 className="text-sm font-black text-slate-800 dark:text-white uppercase tracking-wider">{getGroupName(groupName)}</h4>
                        </div>
                        <div className="grid grid-cols-1 gap-3">
                            {items.map(([key, prop]) => (
                                <div key={key} className="flex flex-col p-4 rounded-2xl bg-white dark:bg-slate-800/30 border border-slate-200 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 transition-colors shadow-sm">
                                    <div className="flex justify-between items-start mb-2">
                                        <div className="flex-1">
                                            <span className="text-xs font-bold text-slate-700 dark:text-slate-200 block mb-1">{tProp(key)}</span>

                                            {/* Context Tags */}
                                            <div className="flex flex-wrap gap-2">
                                                {prop.standard && (
                                                    <span className="text-[9px] font-medium text-slate-500 bg-slate-100 dark:bg-slate-900 px-1.5 py-0.5 rounded border border-slate-200 dark:border-slate-700 flex items-center gap-1">
                                                        <FileText size={8} /> {prop.standard}
                                                    </span>
                                                )}
                                                {prop.temperature && (
                                                    <span className="text-[9px] font-medium text-slate-500 bg-slate-100 dark:bg-slate-900 px-1.5 py-0.5 rounded border border-slate-200 dark:border-slate-700 flex items-center gap-1">
                                                        <Flame size={8} /> {prop.temperature}
                                                    </span>
                                                )}
                                                {prop.referenceId && (
                                                    <span className="text-[9px] font-medium text-slate-500 bg-slate-100 dark:bg-slate-900 px-1.5 py-0.5 rounded border border-slate-200 dark:border-slate-700 flex items-center gap-1" title={t('referenceId')}>
                                                        <Hash size={8} /> {prop.referenceId}
                                                    </span>
                                                )}
                                            </div>
                                        </div>

                                        {/* Value Display - Inline Units */}
                                        <div className="text-right">
                                            <div className="flex items-baseline justify-end gap-1.5">
                                                <span className="font-mono font-black text-lg text-slate-900 dark:text-white leading-none tracking-tight">
                                                    {prop.value}
                                                </span>
                                                {prop.unit && <span className="text-xs font-bold text-slate-400 select-none ml-0.5">{prop.unit}</span>}
                                            </div>
                                        </div>
                                    </div>

